// ── BỘ CÂU HỎI CHỨNG CHỈ HÀNH NGHỀ XÂY DỰNG ──
// Nguồn: Quyết định 702/QĐ-BXD - Bộ Xây dựng
// 345 câu mẫu (ưu tiên giao thông)
const CERT_QUESTIONS_XD = [{"id":11,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, công tác nào sau đây ở giai đoạn thực hiện dự án?","options":["Thanh toán khối lượng xây lắp hoàn thành","Giám sát thi công xây dựng;","Vận hành, chạy thử; nghiệm thu hoàn thành công trình xây dựng","Tất cả các công tác trên"],"answer":3,"explain":""},{"id":12,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, công trình xây dựng được phân cấp phục vụ quản lý hoạt động đầu tư xây dựng trên cơ sở các căn cứ nào?","options":["Quy mô, mức độ quan trọng, thông số kỹ thuật của công trình","Thời hạn sử dụng, vật liệu","Yêu cầu xây dựng công trình","Tất cả các căn cứ trên"],"answer":0,"explain":""},{"id":13,"cat":"Giám sát thi công","text":"Việc phân loại công trình xây dựng theo quy định của pháp luật về xây dựng trên cơ sở tiêu chí nào?","options":["Theo tính chất kết cấu và công năng sử dụng công trình","Theo kiến trúc công trình","Do người quyết định đầu tư quy định","Do chủ đầu tư quy định"],"answer":0,"explain":""},{"id":14,"cat":"Giám sát thi công","text":"Những dự án đầu tư xây dựng nào có thể được phân chia thành các dự án thành phần hoặc phân kỳ đầu tư để quản lý thực hiện như một dự án độc lập?","options":["Dự án quan trọng quốc gia, dự án nhóm A","Khi mỗi dự án thành phần có thể vận hành, khai thác độc lập","Dự án nhóm B, C","Cả 3 phương án a, b và c"],"answer":1,"explain":""},{"id":15,"cat":"Giám sát thi công","text":"Dự án đầu tư xây dựng phải đáp ứng các yêu cầu nào dưới đây?","options":["Phù hợp với quy hoạch và kế hoạch sử dụng đất tại địa phương nơi có dự án đầu tư xây dựng","Có phương án công nghệ và phương án thiết kế xây dựng phù hợp","Bảo đảm chất lượng, an toàn trong xây dựng và bảo vệ môi trường","Cả 3 phương án trên"],"answer":3,"explain":""},{"id":16,"cat":"Giám sát thi công","text":"Các dự án đầu tư xây dựng có quy mô nhóm nào yêu cầu phải lập Báo cáo nghiên cứu tiền khả thi để trình cấp có thẩm quyền quyết định hoặc chấp thuận chủ trương đầu tư?","options":["Dự án quan trọng quốc gia,","Dự án PPP theo quy định của pháp luật về đầu tư theo phương thức đối tác công tư","Dự án nhóm A sử dụng vốn đầu tư công","Cả 3 phương án trên"],"answer":3,"explain":""},{"id":17,"cat":"Giám sát thi công","text":"Trừ trường hợp người quyết định đầu tư có yêu cầu lập Báo cáo nghiên cứu khả thi đầu tư xây dựng, dự án đầu tư xây dựng công trình chỉ cần yêu cầu lập Báo cáo kinh tế - kỹ thuật đầu tư xây dựng gồm trường hợp nào sau đây?","options":["Dự án đầu tư xây dựng sử dụng cho mục đích tôn giáo","Dự án đầu tư xây dựng mới, sửa chữa, cải tạo, nâng cấp có tổng mức đầu tư dưới 15 tỷ đồng (không bao gồm tiền sử dụng đất);","Cả trường hợp a và b","Không bao gồm a và b"],"answer":2,"explain":""},{"id":18,"cat":"Giám sát thi công","text":"Đối với dự án đầu tư xây dựng sử dụng vốn nhà nước ngoài đầu tư công, cơ quan chuyên môn về xây dựng thẩm định đối với dự án nào sau đây?","options":["Dự án từ nhóm B trở lên;","Dự án có công trình ảnh hưởng lớn đến an toàn, lợi ích cộng đồng thuộc chuyên ngành quản lý;","Đáp án a và b đúng","Các dự án trên địa bàn phụ trách"],"answer":2,"explain":""},{"id":19,"cat":"Giám sát thi công","text":"Đối với dự án đầu tư xây dựng sử dụng vốn đầu tư công, cơ quan chuyên môn về xây dựng dựng thuộc Bộ quản lý công trình xây dựng chuyên ngành thẩm định đối với dự án nào sau đây?","options":["Dự án nhóm A; dự án nhóm B do người đứng đầu cơ quan trung ương quyết định đầu tư hoặc phân cấp, ủy quyền quyết định đầu tư;","Dự án được đầu tư xây dựng trên địa bàn hành chính từ 02 tỉnh trở lên;","Dự án do Thủ tướng Chính phủ giao;","Bao gồm tất cả các dự án trên."],"answer":3,"explain":""},{"id":20,"cat":"Giám sát thi công","text":"Đối với dự án quan trọng quốc gia có công nghệ hạn chế chuyển giao sử dụng vốn đầu tư công thì cơ quan nào sau đây thẩm định thiết kế công nghệ?","options":["Sở Xây dựng","Cơ quan chuyên môn trực thuộc người quyết định đầu tư","Chủ đầu tư xây dựng","Hội đồng thẩm định nhà nước"],"answer":3,"explain":""},{"id":21,"cat":"Giám sát thi công","text":"Đối với các dự án đầu tư xây dựng điều chỉnh, cơ quan chuyên môn về xây dựng thẩm định Báo cáo nghiên cứu khả thi điều chỉnh trong trường hợp nào sau đây?","options":["Khi điều chỉnh dự án có thay đổi về mục tiêu, quy mô sử dụng đất, quy mô đầu tư xây dựng;","Khi điều chỉnh làm tăng tổng mức đầu tư dự án đối với dự án sử dụng vốn đầu tư công, dự án sử dụng vốn nhà nước ngoài đầu tư công;","Cả trường hợp a và b","Không bao gồm các trường hợp ở trên"],"answer":2,"explain":""},{"id":22,"cat":"Giám sát thi công","text":"Đối với nguồn vốn khác thì cơ quan chuyên môn về xây dựng thuộc các Bộ quản lý công trình xây dựng chuyên ngành thẩm định những dự án nào?","options":["Dự án đầu tư xây dựng có công trình cấp đặc biệt, cấp I và cấp II, dự án được đầu tư xây dựng trên địa bàn hành chính của 02 tỉnh trở lên","Dự án do Quốc hội, Thủ tướng Chính phủ chấp thuận chủ trương đầu tư; dự án nhóm A; dự án đầu tư xây dựng có công trình cấp đặc biệt, cấp I; dự án được đầu tư xây dựng trên địa bàn hành chính của 02 tỉnh trở lên","Dự án đầu tư xây dựng có công trình từ cấp III trở lên và dự án được đầu tư xây dựng trên địa bàn hành chính của 02 tỉnh trở lên","Chỉ dự án nhóm A"],"answer":1,"explain":""},{"id":23,"cat":"Giám sát thi công","text":"Cơ quan chuyên môn về xây dựng thẩm định Báo cáo nghiên cứu khả thi đầu tư xây dựng đối với các dự án nào sau đây?","options":["Dự án sử dụng vốn đầu tư công; Dự án đầu tư xây dựng có quy mô từ nhóm B trở lên hoặc có công trình ảnh hưởng lớn đến an toàn, lợi ích cộng đồng sử dụng vốn nhà nước ngoài đầu tư công;","Dự án PPP; Dự án đầu tư xây dựng có quy mô lớn hoặc có công trình ảnh hưởng lớn đến an toàn, lợi ích cộng đồng sử dụng vốn khác,","Cả a và b","Không bao gồm a và b"],"answer":2,"explain":""},{"id":24,"cat":"Giám sát thi công","text":"Đối với dự án sử dụng vốn đầu tư công, dự án sử dụng vốn nhà nước ngoài đầu tư công chỉ cần lập Báo cáo kinh tế - kỹ thuật, người quyết định đầu tư thẩm định những nội dung nào sau đây?","options":["Sự phù hợp về quy hoạch, mục tiêu, quy mô đầu tư và các yêu cầu khác được xác định trong quyết định hoặc chấp thuận chủ trương đầu tư xây dựng;","Sự đáp ứng yêu cầu của thiết kế bản vẽ thi công về bảo đảm an toàn công trình và biện pháp bảo đảm an toàn công trình lân cận;","Việc lập tổng mức đầu tư xây dựng, xác định giá trị tổng mức đầu tư xây dựng;","Tất cả các nội dung ở trên"],"answer":3,"explain":""},{"id":25,"cat":"Giám sát thi công","text":"Hợp đồng trong hoạt động xây dựng theo hình thức giá có những loại nào?","options":["Hình thức trọn gói, hình thức theo thời gian","Hình thức điều chỉnh giá, Hình thức theo đơn giá cố định","Bao gồm các hình thức nêu tại a và b","Không có hình thức nào nêu tại a và b"],"answer":2,"explain":""},{"id":26,"cat":"Giám sát thi công","text":"Chức năng, nhiệm vụ của Ban QLDA chuyên ngành, ban QLDA khu vực do ai quy định?","options":["Người có thẩm quyền quyết định đầu tư","Người quyết định thành lập Ban QLDA chuyên ngành, ban QLDA khu vực","Cơ quan chuyên môn về xây dựng","Chủ đầu tư"],"answer":1,"explain":""},{"id":28,"cat":"Giám sát thi công","text":"Chủ thể nào phải chịu trách nhiệm chính về an toàn lao động trên công trường?","options":["Chủ đầu tư","Nhà thầu thi công xây dựng công trình","Nhà thầu tư vấn giám sát thi công xây dựng công trình","Cả a, b và c"],"answer":1,"explain":""},{"id":29,"cat":"Giám sát thi công","text":"Các dự án đầu tư xây dựng thuộc Tập đoàn kinh tế, Tổng công ty nhà nước phải tuân thủ theo các quy định nào?","options":["Điều lệ, quy chế hoạt động của Tập đoàn, Tổng công ty","Theo quy định Pháp luật về xây dựng, pháp luật về đấu thầu và pháp luật khác liên quan","Bao gồm a và b","Chỉ tuân thủ quy định của pháp luật về xây dựng"],"answer":2,"explain":""},{"id":30,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, đối với nguồn vốn khác, chủ đầu tư có thể áp dụng hình thức quản lý dự án nào sau đây?","options":["Chủ đầu tư sử dụng tư cách pháp nhân của mình và bộ máy chuyên môn trực thuộc có đủ điều kiện, năng lực","Chủ đầu tư được thuê tổ chức, cá nhân có đủ điều kiện năng lực","Đáp án a và b là đúng","Đáp án a và b là sai"],"answer":2,"explain":""},{"id":31,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, đối với các gói thầu sử dụng vốn nhà nước ngoài đầu tư công thì hợp đồng xây dựng được ký kết vào thời điểm nào?","options":["Sau khi hoàn thành việc lựa chọn nhà thầu","Sau khi hoàn thành việc lựa chọn nhà thầu và kết thúc đàm phán hợp đồng","Trước khi khởi công xây dựng công trình","Cả 3 phương án a, b và c"],"answer":1,"explain":""},{"id":35,"cat":"Giám sát thi công","text":"Đối với các gói thầu sử dụng vốn đầu tư công, việc điều chỉnh đơn giá thực hiện hợp đồng chỉ được áp dụng đối với loại hợp đồng nào?","options":["Hợp đồng theo đơn giá cố định; hợp đồng theo thời gian","Hợp đồng theo đơn giá điều chỉnh, hợp đồng theo thời gian","Cả a và b","a hoặc b"],"answer":1,"explain":""},{"id":36,"cat":"Giám sát thi công","text":"Trước khi ký kết hợp đồng EPC các bên phải thỏa thuận cụ thể những nội dung chủ yếu nào sau đây?","options":["Phạm vi công việc dự kiến thực hiện theo hợp đồng EPC; Vị trí xây dựng, hướng tuyến công trình, loại, cấp công trình; quy mô, công suất và phương án sản phẩm được lựa chọn, năng lực khai thác sử dụng;","Các thông tin về các tài liệu, số liệu về điều kiện tự nhiên, địa chất công trình, địa chất thủy văn, thủy văn của khu vực nơi xây dựng công trình; Các yêu cầu về thiết kế xây dựng và một số thông số thiết kế ban đầu;","Bao gồm cả nội dung a và b","Không bao gồm nội dung a và b"],"answer":2,"explain":""},{"id":37,"cat":"Giám sát thi công","text":"Đối với các gói thầu thi công xây dựng sử dụng vốn đầu tư công, tiến độ thực hiện hợp đồng được điều chỉnh trong các trường hợp nào?","options":["Trong quá trình thực hiện hợp đồng xảy ra các trường hợp bất khả kháng","Do bên giao thầu thay đổi thiết kế hoặc bàn giao mặt bằng không đúng với thỏa thuận trong hợp đồng","Đáp án a và b đúng","Các trường hợp trên đều không đúng"],"answer":2,"explain":""},{"id":38,"cat":"Giám sát thi công","text":"Hợp đồng EPC là loại hợp đồng thực hiện những công việc gì?","options":["Thiết kế và thi công xây dựng","Thiết kế và cung cấp vật tư, thiết bị","Thiết kế - mua sắm vật tư, thiết bị - thi công xây dựng công trình","Lập dự án, thiết kế, cung cấp vật tư, thiết bị và thi công xây dựng"],"answer":2,"explain":""},{"id":39,"cat":"Giám sát thi công","text":"Đối với hợp đồng EPC ngoài tiến độ thi công cho từng giai đoạn của tổng thầu, nhà thầu còn phải lập tiến độ thực hiện cho những công việc nào dưới đây?","options":["Tiến độ cho công việc thiết kế","Tiến độ cho công việc cung cấp thiết bị và thi công xây dựng","Tiến độ cho công việc thiết kế - mua sắm vật tư, thiết bị - thi công xây dựng công trình","Tiến độ cho công việc thiết kế và thi công xây dựng"],"answer":2,"explain":""},{"id":40,"cat":"Giám sát thi công","text":"Đối với các gói thầu sử dụng vốn đầu tư công, nhà thầu chính có quyền giao 100% công việc của hợp đồng đã ký kết với bên giao thầu cho nhà thầu phụ không?","options":["Có","Không","Tùy thuộc vào tình hình cụ thể và nhà thầu chính quyết định","Do bên giao thầu và bên nhận thầu thỏa thuận"],"answer":1,"explain":""},{"id":41,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật Xây dựng hiện hành, nhà thầu nào có trách nhiệm lập biện pháp an toàn cho người và thiết bị thi công công trình trên công trường xây dựng?","options":["Nhà thầu thiết kế","Nhà thầu thi công xây dựng","Chủ đầu tư","Tư vấn giám sát thi công xây dựng"],"answer":1,"explain":""},{"id":42,"cat":"Giám sát thi công","text":"Hồ sơ trình thẩm định báo cáo nghiên cứu khả thi đầu tư xây dựng không bao gồm tài liệu nào dưới đây?","options":["Tờ trình thẩm định báo cáo nghiên cứu khả thi","Thiết kế cơ sở của dự án","Thiết kế kỹ thuật của dự án","Giấy tờ liên quan đến đất đai"],"answer":2,"explain":""},{"id":43,"cat":"Giám sát thi công","text":"Công tác nào sau đây không nằm trong giai đoạn thực hiện dự án đầu tư xây dựng?","options":["Thẩm định, phê duyệt thiết kế bản vẽ thi công và dự toán","Lựa chọn nhà thầu thi công xây dựng","Thẩm định, phê duyệt dự án","Nghiệm thu công việc xây dựng"],"answer":2,"explain":""},{"id":44,"cat":"Giám sát thi công","text":"Đối với các bộ, cơ quan ở trung ương: Ban quản lý dự án chuyên ngành, Ban quản lý dự án khu vực được thành lập theo tiêu chí nào sau đây?","options":["Phù hợp với các chuyên ngành thuộc lĩnh vực quản lý","Theo yêu cầu về xây dựng cơ sở vật chất, hạ tầng tại các vùng, khu vực","Đáp án a hoặc b","Đáp án a và b"],"answer":2,"explain":""},{"id":49,"cat":"Giám sát thi công","text":"Những cá nhân nào dưới đây không bắt buộc phải có chứng chỉ hành nghề hoạt động xây dựng?","options":["Chủ nhiệm thiết kế xây dựng công trình","Chủ trì thiết kế bộ môn trong công trình xây dựng","Cá nhân giám sát thi công của nhà thầu thi công xây dựng","Cán bộ tư vấn giám sát thi công xây dựng"],"answer":2,"explain":""},{"id":50,"cat":"Giám sát thi công","text":"Chủ nhiệm thiết kế xây dựng hạng 1 phải đáp ứng các điều kiện gì?","options":["Có trình độ đại học thuộc chuyên ngành phù hợp","Có thời gian làm công tác thiết kế xây dựng tối thiểu 7 năm","Đã làm chủ nhiệm thiết kế phần việc thuộc lĩnh vực phù hợp ít nhất 01 công trình từ cấp I trở lên hoặc 02 công trình từ cấp II trở lên","Cả a, b và c"],"answer":3,"explain":""},{"id":51,"cat":"Giám sát thi công","text":"Điều kiện nào dưới đây không yêu cầu đối với giám đốc QLDA hạng I?","options":["Đã là chủ nhiệm lập dự án ít nhất 1 dự án nhóm A hoặc 2 dự án nhóm B","Có trình độ đại học chuyên ngành xây dựng","Có thời gian tham gia thiết kế hoặc thi công xây dựng tối thiểu 7 năm","Đã có chứng chỉ hành nghề thiết kế xây dựng hạng I hoặc giám sát thi công xây dựng hạng I"],"answer":0,"explain":""},{"id":52,"cat":"Giám sát thi công","text":"Chủ thể nào sau đây có trách nhiệm lập bản vẽ hoàn công công trình?","options":["Chủ đầu tư","Nhà thầu thiết kế xây dựng","Nhà thầu thi công xây dựng","Nhà thầu tư vấn giám sát thi công xây dựng"],"answer":2,"explain":""},{"id":53,"cat":"Giám sát thi công","text":"Chủ thể nào có trách nhiệm lập tiến độ chi tiết thi công xây dựng công trình?","options":["Chủ đầu tư","Nhà thầu thiết kế xây dựng công trình","Nhà thầu thi công xây dựng công trình","Nhà thầu tư vấn giám sát thi công xây dựng"],"answer":2,"explain":""},{"id":54,"cat":"Giám sát thi công","text":"Đối với công trình xây dựng sử dụng vốn đầu tư công, công trình xây dựng sử dụng vốn nhà nước ngoài đầu tư công, chủ đầu tư thẩm định thiết kế xây dựng triển khai sau thiết kế cơ sở đối với các nội dung nào sau đây?","options":["Sự đáp ứng yêu cầu của thiết kế xây dựng với nhiệm vụ thiết kế, quy định tại hợp đồng thiết kế và quy định của pháp luật có liên quan;","Sự phù hợp của thiết kế xây dựng với yêu cầu về dây chuyền và thiết bị công nghệ (nếu có);","Việc lập dự toán xây dựng công trình; sự phù hợp của giá trị dự toán xây dựng công trình với giá trị tổng mức đầu tư xây dựng; xác định giá trị dự toán xây dựng công trình.","Bao gồm tất cả các nội dung ở trên"],"answer":3,"explain":""},{"id":55,"cat":"Giám sát thi công","text":"Số bước thiết kế xây dựng do ai quyết định?","options":["Người quyết định đầu tư khi phê duyệt dự án","Chủ đầu tư khi triển khai thực hiện dự án","Tổ chức tư vấn khi lập dự án đầu tư xây dựng","Cả 3 phương án trên đều sai"],"answer":0,"explain":""},{"id":56,"cat":"Giám sát thi công","text":"Chủ thể nào có trách nhiệm thực hiện bảo hành công trình xây dựng?","options":["Chủ đầu tư xây dựng công trình","Nhà thầu thi công xây dựng công trình","Nhà thầu thiết kế xây dựng công trình","Cả 3 phương án trên đều đúng"],"answer":1,"explain":""},{"id":57,"cat":"Giám sát thi công","text":"Việc điều chỉnh dự án sử dụng vốn khác phải đảm bảo yêu cầu nào sau đây?","options":["Các yêu cầu về quy hoạch","Các yêu cầu về an toàn, bảo vệ môi trường","Các yêu cầu về phòng, chống cháy, nổ, quốc phòng, an ninh","Cả 3 phương án a, b và c"],"answer":3,"explain":""},{"id":58,"cat":"Giám sát thi công","text":"Dự án đầu tư xây dựng sử dụng vốn đầu tư công được xem xét điều chỉnh trong những trường hợp nào?","options":["Do ảnh hưởng của thiên tai, sự cố môi trường, địch họa, hỏa hoạn và các yếu tố bất khả kháng khác","Xuất hiện yếu tố mang lại hiệu quả cao hơn cho dự án khi đã được chủ đầu tư chứng minh về hiệu quả tài chính, kinh tế - xã hội do việc điều chỉnh dự án mang lại","Khi quy hoạch xây dựng thay đổi có ảnh hưởng trực tiếp tới dự án","Cả a, b và c"],"answer":3,"explain":""},{"id":59,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về môi trường, những loại dự án nào phải lập báo cáo đánh giá tác động môi trường?","options":["Dự án quan trọng quốc gia","Dự án đầu tư xây dựng đô thị mới, khu dân cư tập trung","Dự án khai thác, sử dụng nước dưới đất và tài nguyên thiên nhiên có quy mô lớn","Cả a, b và c"],"answer":3,"explain":""},{"id":60,"cat":"Giám sát thi công","text":"Trường hợp công việc được xác định rõ về số lượng, khối lượng, thời gian thực hiện ngắn thì áp dụng hình thức hợp đồng nào là hợp lý nhất?","options":["Hợp đồng trọn gói","Hợp đồng theo đơn giá","Hợp đồng theo thời gian","Hợp đồng theo đơn giá cố định"],"answer":0,"explain":""},{"id":61,"cat":"Giám sát thi công","text":"Trường hợp công việc chưa đủ điều kiện để xác định chính xác về số lượng hoặc khối lượng thì nên áp dụng hình thức hợp đồng nào là thích hợp nhất?","options":["Hợp đồng trọn gói","Hợp đồng theo đơn giá cố định","Hợp đồng theo thời gian","Hợp đồng theo tỷ lệ phần trăm"],"answer":1,"explain":""},{"id":62,"cat":"Giám sát thi công","text":"Bên giao thầu có quyền chấm dứt hợp đồng trong các trường hợp nào sau đây?","options":["Bên nhận thầu bị phá sản hoặc Bên nhận thầu không thực hiện công việc theo hợp đồng 45 ngày liên tục mà không có lý do","Bên nhận thầu chuyển nhượng lợi ích của hợp đồng xây dựng cho bên khác mà không có nêu trong hợp đồng đã ký kết","Bao gồm các đáp án a và b","Việc chấm dứt hợp đồng là do bên giao thầu quyết định"],"answer":2,"explain":""},{"id":63,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, bản vẽ thiết kế xây dựng trong hồ sơ đề nghị cấp giấy phép xây dựng là bản vẽ của bước thiết kế nào?","options":["Thiết kế cơ sở","Thiết kế kỹ thuật hoặc thiết kế bản vẽ thi công đã được thẩm định, phê duyệt theo quy định","Thiết kế bản vẽ thi công đã được thẩm định, phê duyệt","Một trong phương án a, b hoặc c"],"answer":1,"explain":""},{"id":64,"cat":"Giám sát thi công","text":"Khi khởi công xây dựng công trình yêu cầu phải có các điều kiện nào dưới đây?","options":["Có mặt bằng xây dựng để bàn giao toàn bộ hoặc từng phần theo tiến độ xây dựng","Có thiết kế bản vẽ thi công của hạng mục công trình, công trình khởi công đã được phê duyệt","Đáp ứng cả điều kiện nêu tại a và b","Chỉ cần đáp ứng điều kiện a hoặc b"],"answer":2,"explain":""},{"id":80,"cat":"Giám sát thi công","text":"Trong trường hợp thuê tư vấn quản lý dự án, chủ đầu tư có trách nhiệm như thế nào là đúng sau đây?","options":["Giám sát việc thực hiện hợp đồng tư vấn quản lý dự án;","Xử lý các vấn đề có liên quan giữa tổ chức tư vấn quản lý dự án với các nhà thầu trong quá trình thực hiện dự án;","Giám sát việc thực hiện hợp đồng của các nhà thầu thi công và giám sát thi công","Xử lý các vấn đề có liên quan giữa tổ chức tư vấn quản lý dự án với chính quyền địa phương trong quá trình thực hiện dự án;"],"answer":0,"explain":""},{"id":81,"cat":"Giám sát thi công","text":"Cá nhân đề nghị cấp chứng chỉ hành nghề hoạt động xây dựng yêu cầu phải đáp ứng các điều kiện chung gì?","options":["Có đủ năng lực hành vi dân sự theo quy định của pháp luật","Có trình độ chuyên môn được đào tạo, thời gian và kinh nghiệm tham gia công việc phù hợp với nội dung đề nghị cấp chứng chỉ hành nghề và phải đạt kết quả sát hạch theo quy định","Bao gồm a và b","Chỉ cần đạt được kết quả sát hạch theo quy định là đủ"],"answer":2,"explain":""},{"id":82,"cat":"Giám sát thi công","text":"Tổ chức đề nghị cấp chứng chỉ năng lực hoạt động xây dựng yêu cầu phải đáp ứng các điều kiện gì?","options":["Những cá nhân chủ chốt của tổ chức phải có chứng chỉ hành nghề phù hợp với lĩnh vực và hạng năng lực mà tổ chức đề nghị cấp chứng chỉ năng lực","Tổ chức đã thực hiện công việc tương tự loại, cấp công trình","Phải có thời gian tham gia hoạt động xây dựng tối thiểu 3 năm","Đáp ứng cả điều kiện a và b ở trên"],"answer":3,"explain":""},{"id":83,"cat":"Giám sát thi công","text":"Nhà thầu phụ phải chịu trách nhiệm với ai về công việc do mình thực hiện?","options":["Chủ đầu tư","Thầu chính hoặc tổng thầu","Chủ đầu tư và thầu chính hoặc tổng thầu","Chịu trách nhiệm với ai là căn cứ vào các điều khoản cam kết trong hợp đồng xây dựng"],"answer":1,"explain":""},{"id":84,"cat":"Giám sát thi công","text":"Trường hợp phải thuê thầu phụ để thực hiện một số phần việc trong hợp đồng đã ký kết với chủ đầu tư thì cần phải có chấp thuận của ai?","options":["Người quyết định đầu tư","Chủ đầu tư","Người quyết định đầu tư hoặc chủ đầu tư tùy thuộc vào từng gói thầu","Không cần phải có sự chấp thuận của cơ quan, tổ chức nào"],"answer":1,"explain":""},{"id":85,"cat":"Giám sát thi công","text":"Bảo đảm thực hiện hợp đồng xây dựng phải được nộp cho bên giao thầu khi nào?","options":["Trước thời điểm hợp đồng có hiệu lực","Sau khi hợp đồng được ký kết","Trước khi khởi công xây dựng công trình","Bao gồm cả a, b và c"],"answer":0,"explain":""},{"id":86,"cat":"Giám sát thi công","text":"Bảo đảm thực hiện hợp đồng của nhà thầu thi công xây dựng có hiệu lực đến khi nào?","options":["Đến khi nhà thầu đã hoàn thành các nghĩa vụ theo hợp đồng","Sau khi chủ đầu tư đã nhận được bảo đảm bảo hành của nhà thầu","Đáp án a hoặc b do hai bên thỏa thuận trong hợp đồng","Sau khi công việc theo hợp đồng đã hoàn thành bàn giao chủ chủ đầu tư"],"answer":2,"explain":""},{"id":87,"cat":"Giám sát thi công","text":"Cá nhân không có chứng chỉ hành nghề được tham gia các hoạt động xây dựng theo quy định nào sau đây là đúng?","options":["Được tham gia các hoạt động xây dựng thuộc lĩnh vực phù hợp với chuyên ngành được đào tạo, phù hợp với quy định của Bộ luật Lao động","Không được hành nghề độc lập, không được đảm nhận chức danh theo quy định phải có chứng chỉ hành nghề.","Tuân thủ cả quy định a và b","Được tham gia các hoạt động xây dựng đối với những dự án nhóm C, công trình cấp II trở xuống"],"answer":2,"explain":""},{"id":88,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật xây dựng, cá nhân khi thực hiện các hoạt động xây dựng nào sau đây không cần phải có chứng chỉ hành nghề?","options":["Thiết kế, giám sát hệ thống thông tin liên lạc, viễn thông trong công trình","Thiết kế, giám sát thi công hệ thống kết cấu công trình xây dựng","Không nội dung nào ở trên","Cả a và b đúng"],"answer":0,"explain":""},{"id":89,"cat":"Giám sát thi công","text":"Tổ chức hoạt động xây dựng mới được thành lập có những cá nhân có chứng chỉ hành nghề hạng 1 phù hợp với lĩnh vực mà tổ chức đề nghị cấp chứng chỉ năng lực hoạt động xây dựng, nhưng chưa ký hợp đồng để thực hiện bất kể công việc gì trong hoạt động đầu tư xây dựng thì có được cấp chứng chỉ năng lực hoạt động xây dựng hạng 1 không?","options":["Có","Không","Có, nhưng chỉ được xem cấp chứng chỉ hành năng lực cho lĩnh vực định giá xây dựng","Có, nhưng chỉ được xem cấp chứng chỉ hành năng lực cho các lĩnh vực giám sát thi công xây dựng, kiểm định xây dựng"],"answer":1,"explain":""},{"id":90,"cat":"Giám sát thi công","text":"Bước thiết kế công trình xây dựng nào mới đủ điều kiện để khởi công xây dựng công trình?","options":["Thiết kế cơ sở","Thiết kế kỹ thuật","Thiết kế bản vẽ thi công","Một trong ba bước thiết kế trên đều được"],"answer":2,"explain":""},{"id":99,"cat":"Giám sát thi công","text":"Đơn vị nào có trách nhiệm tổ chức giám sát khảo sát xây dựng?","options":["Chủ đầu tư;","Nhà thầu giám sát thi công;","Nhà thầu thiết kế xây dựng;","Nhà thầu khảo sát;"],"answer":0,"explain":""},{"id":100,"cat":"Giám sát thi công","text":"Tùy theo quy mô và loại hình khảo sát, chủ đầu tư có trách nhiệm tổ chức giám sát khảo sát xây dựng theo các nội dung nào dưới đây?","options":["Kiểm tra năng lực thực tế của nhà thầu khảo sát xây dựng bao gồm nhân lực, thiết bị khảo sát tại hiện trường, phòng thí nghiệm;","Theo dõi, kiểm tra việc thực hiện khảo sát xây dựng bao gồm: Vị trí khảo sát, khối lượng khảo sát, quy trình thực hiện khảo sát, lưu giữ số liệu khảo sát và mẫu thí nghiệm;","Theo dõi, kiểm tra việc thực hiện khảo sát xây dựng bao gồm: Kiểm tra thí nghiệm trong phòng và thí nghiệm hiện trường; kiểm tra công tác đảm bảo an toàn lao động, an toàn môi trường trong quá trình thực hiện khảo sát.","Tất cả những nội dung trên;"],"answer":3,"explain":""},{"id":101,"cat":"Giám sát thi công","text":"Đơn vị nào lập phương án kỹ thuật khảo sát xây dựng?","options":["Chủ đầu tư;","Nhà thầu khảo sát;","Nhà thầu thiết kế xây dựng;","Nhà thầu giám sát thi công;"],"answer":1,"explain":""},{"id":155,"cat":"Giám sát thi công","text":"Tổ chức nào không được thực hiện thẩm tra thiết kế, dự toán công trình X?","options":["Tổ chức đã thiết kế xây dựng công trình X","Cơ quan chuyên môn về xây dựng","Ban quản lý dự án đầu tư xây dựng thuộc chủ đầu tư","Tổ chức tư vấn giám sát thi công xây dựng công trình X"],"answer":0,"explain":""},{"id":156,"cat":"Giám sát thi công","text":"Cơ quan chuyên môn về xây dựng theo thẩm quyền thực hiện việc thẩm định thiết kế xây dựng điều chỉnh đối với các trường hợp nào sau đây?","options":["Điều chỉnh, bổ sung thiết kế xây dựng có thay đổi về địa chất công trình, tải trọng thiết kế, giải pháp kết cấu, vật liệu sử dụng cho kết cấu chịu lực và biện pháp tổ chức thi công có ảnh hưởng đến an toàn chịu lực của công trình","Khi điều chỉnh dự án đầu tư xây dựng có yêu cầu điều chỉnh thiết kế cơ sở","Cả trường hợp a và b","Không trường hợp nào ở trên"],"answer":2,"explain":""},{"id":157,"cat":"Giám sát thi công","text":"Hồ sơ trình thẩm định Báo cáo nghiên cứu khả thi đầu tư xây dựng tại cơ quan chuyên môn về xây dựng bao gồm nội dung nào sau đây?","options":["Các văn bản thỏa thuận, xác nhận về đấu nối hạ tầng kỹ thuật của dự án;","Văn bản ý kiến về giải pháp phòng cháy, chữa cháy của thiết kế cơ sở; văn bản kết quả thực hiện thủ tục về đánh giá tác động môi trường theo quy định của pháp luật về bảo vệ môi trường;","Bao gồm cả a và b","Không bao gồm các nội dung trên"],"answer":2,"explain":""},{"id":180,"cat":"Giám sát thi công","text":"Những người nào sau đây tham gia và ký biên bản nghiệm thu công việc xây dựng","options":["Người giám sát thi công xây dựng công trình và người phụ trách kỹ thuật thi công trực tiếp của nhà thầu thi công xây dựng công trình","Người của Chủ đầu tư/Ban quản lý dự án, người giám sát thi công xây dựng công trình và người phụ trách kỹ thuật thi công trực tiếp của nhà thầu thi công xây dựng công trình","Người của Chủ đầu tư/Ban quản lý dự án và người phụ trách kỹ thuật thi công trực tiếp của nhà thầu thi công xây dựng công trình","Cả ba đáp án trên"],"answer":0,"explain":""},{"id":181,"cat":"Giám sát thi công","text":"Ai là người có trách nhiệm tổ chức lập hồ sơ hoàn thành công trình xây dựng?","options":["Nhà thầu thi công xây dựng","Chủ đầu tư","Nhà thầu giám sát thi công xây dựng","Cơ quan quản lý nhà nước có thẩm quyền"],"answer":1,"explain":""},{"id":182,"cat":"Giám sát thi công","text":"Thời hạn bảo trì công trình được tính như thế nào?","options":["Sau khi kết thúc thời hạn bảo hành cho đến khi hết niên hạn sử dụng công trình.","Từ ngày nghiệm thu đưa công trình xây dựng vào sử dụng cho đến khi hết niên hạn sử dụng công trình.","Từ ngày chủ đầu tư bàn giao công trình cho chủ sở hữu hoặc người quản lý sử dụng công trình.","Từ ngày có văn bản chấp thuận kết quả nghiệm thu của chủ đầu tư"],"answer":1,"explain":""},{"id":183,"cat":"Giám sát thi công","text":"Việc áp dụng quy chuẩn kỹ thuật trong hoạt động đầu tư xây dựng là:","options":["Bắt buộc","Khuyến khích","Tự nguyện","Thỏa thuận"],"answer":0,"explain":""},{"id":184,"cat":"Giám sát thi công","text":"Quy định áp dụng Tiêu chuẩn kỹ thuật trong hoạt động đầu tư xây dựng như thế nào?","options":["Bắt buộc đối với các tiêu chuẩn được viện dẫn trong quy chuẩn kỹ thuật hoặc văn bản quy phạm pháp luật khác có liên quan","Khuyến khích áp dụng","Theo nguyên tắc tự nguyện","Đáp án a và c"],"answer":3,"explain":""},{"id":185,"cat":"Giám sát thi công","text":"Những loại tiêu chuẩn nào sau đây bắt buộc áp dụng?","options":["TCVN","Tiêu chuẩn nước ngoài","Các tiêu chuẩn nằm trong danh mục tiêu chuẩn đã được người quyết định đầu tư phê duyệt","Danh mục tiêu chuẩn do tư vấn thiết kế đệ trình"],"answer":2,"explain":""},{"id":186,"cat":"Giám sát thi công","text":"Nhà thầu thi công phải trình chủ đầu tư chấp thuận những tài liệu nào sau đây?","options":["Kế hoạch tổ chức thí nghiệm và kiểm định chất lượng, quan trắc, đo đạc các thông số kỹ thuật của công trình theo yêu cầu thiết kế và chỉ dẫn kỹ thuật;","Biện pháp kiểm tra, kiểm soát chất lượng vật liệu, sản phẩm, cấu kiện, thiết bị được sử dụng cho công trình; thiết kế biện pháp thi công, trong đó quy định cụ thể các biện pháp, bảo đảm an toàn cho người, máy, thiết bị và công trình;","Kế hoạch kiểm tra, nghiệm thu công việc xây dựng, nghiệm thu giai đoạn thi công xây dựng hoặc bộ phận (hạng mục) công trình xây dựng, nghiệm thu hoàn thành hạng mục công trình, công trình xây dựng;","Toàn bộ các tài liệu nêu trên"],"answer":3,"explain":""},{"id":187,"cat":"Giám sát thi công","text":"Việc giám sát thi công xây dựng công trình phải đảm bảo các yêu cầu nào sau đây?","options":["Thực hiện trong suốt quá trình thi công từ khi khởi công xây dựng, trong thời gian thực hiện cho đến khi hoàn thành và nghiệm thu công việc, công trình xây dựng;","Theo thiết kế xây dựng được phê duyệt, tiêu chuẩn áp dụng, quy chuẩn kỹ thuật, quy định về quản lý, sử dụng vật liệu xây dựng, chỉ dẫn kỹ thuật và hợp đồng xây dựng;","Trung thực khách quan, không vụ lợi;","Tất cả các yêu cầu trên"],"answer":3,"explain":""},{"id":188,"cat":"Giám sát thi công","text":"Nhà thầu giám sát thi công xây dựng có trách nhiệm gì sau đây?","options":["Thực hiện giám sát theo hợp đồng được ký kết","Từ chối nghiệm thu khi công trình không đạt yêu cầu về chất lượng","Giám sát việc thực hiện các quy định về an toàn, bảo vệ môi trường","Tất cả các điều trên"],"answer":3,"explain":""},{"id":189,"cat":"Giám sát thi công","text":"Tổ chức giám sát thi công xây dựng phải độc lập với các nhà thầu thi công xây dựng công trình trong các trường hợp nào sau đây?","options":["Các công trình đầu tư bằng nguồn vốn đầu tư công và nguồn vốn nhà nước ngoài đầu tư công","Các công trình đầu tư bằng nguồn vốn khác","Không trường hợp nào cần","Tất cả các trường hợp trên"],"answer":0,"explain":""},{"id":190,"cat":"Giám sát thi công","text":"Bản vẽ hoàn công là bản vẽ nào sau đây?","options":["Là bản vẽ công trình xây dựng hoàn thành, trong đó thể hiện vị trí, kích thước, vật liệu và thiết bị được sử dụng thực tế","Là bản vẽ của thiết kế kỹ thuật","Là bản vẽ của thiết kế bản vẽ thi công","Tất cả các đáp án trên"],"answer":0,"explain":""},{"id":191,"cat":"Giám sát thi công","text":"Thẩm quyền kiểm tra biện pháp thi công xây dựng của nhà thầu thi công?","options":["Tư vấn thiết kế","Người giám sát thi công xây dựng của chủ đầu tư","Đơn vị kiểm định độc lập","Cả ba đáp án trên"],"answer":1,"explain":""},{"id":192,"cat":"Giám sát thi công","text":"Nhật ký thi công xây dựng công trình do ai lập?","options":["Chủ đầu tư","Nhà thầu thi công xây dựng","Đơn vị tư vấn giám sát lập","Cả ba đáp án trên"],"answer":1,"explain":""},{"id":193,"cat":"Giám sát thi công","text":"Ai là người có thẩm quyền phê duyệt thiết kế biện pháp thi công?","options":["Chủ đầu tư","Nhà thầu thi công xây dựng","Người quyết định đầu tư","Tư vấn giám sát"],"answer":0,"explain":""},{"id":194,"cat":"Giám sát thi công","text":"Nội dung nào sau đây không cần phải đáp ứng khi khởi công công trình?","options":["Có thiết kế bản vẽ thi công của hạng mục công trình, công trình khởi công đã được phê duyệt","Chủ đầu tư đã ký kết hợp đồng với nhà thầu thực hiện các hoạt động xây dựng liên quan đến công trình được khởi công theo quy định của pháp luật","Có hợp đồng với đơn vị cung cấp vật liệu chính của công trình.","Có biện pháp bảo đảm an toàn, bảo vệ môi trường trong quá trình thi công xây dựng"],"answer":2,"explain":""},{"id":195,"cat":"Giám sát thi công","text":"Nội dung nào sau đây phải đáp ứng khi khởi công công trình?","options":["Có mặt bằng xây dựng để bàn giao toàn bộ hoặc từng phần theo tiến độ xây dựng;","Có thiết kế bản vẽ thi công của hạng mục công trình, công trình khởi công đã được phê duyệt;","Chủ đầu tư đã ký kết hợp đồng với nhà thầu thực hiện các hoạt động xây dựng liên quan đến công trình được khởi công theo quy định của pháp luật;","Có tất cả các nội dung ở trên"],"answer":3,"explain":""},{"id":198,"cat":"Giám sát thi công","text":"Nội dung nào sau đây thuộc về nghĩa vụ của nhà thầu giám sát thi công xây dựng công trình?","options":["Nghiệm thu khối lượng thi công xây dựng, phù hợp với tiêu chuẩn áp dụng, quy chuẩn kỹ thuật và theo yêu cầu của tiến độ thi công;","Nghiệm thu khối lượng bảo đảm chất lượng, phù hợp với tiêu chuẩn áp dụng, quy chuẩn kỹ thuật và theo yêu cầu của thiết kế công trình;","Nghiệm thu giá trị thi công xây dựng, phù hợp với tiêu chuẩn áp dụng, quy chuẩn kỹ thuật và theo yêu cầu của thiết kế công trình;","Nghiệm thu khối lượng theo đơn giá được duyệt, phù hợp với tiêu chuẩn áp dụng, quy chuẩn kỹ thuật và theo yêu cầu của thiết kế công trình;"],"answer":1,"explain":""},{"id":199,"cat":"Giám sát thi công","text":"Đối với công tác an toàn và bảo vệ môi trường trên công trường xây dựng, người giám sát có trách nhiệm nào sau đây?","options":["Lập biện pháp và tuân thủ các quy định về an toàn, bảo vệ môi trường.","Giám sát việc thực hiện các quy định về an toàn, bảo vệ môi trường.","Tạm dừng thi công và thông báo kịp thời cho chủ đầu tư để xử lý trong trường hợp phát hiện công trình có nguy cơ xảy ra mất an toàn.","Đáp án b và c."],"answer":3,"explain":""},{"id":200,"cat":"Giám sát thi công","text":"Nội dung nào sau đây không thuộc nghĩa vụ của nhà thầu giám sát thi công xây dựng công trình?","options":["Thực hiện giám sát theo đúng hợp đồng.","Từ chối nghiệm thu khi công trình không đạt yêu cầu chất lượng.","Từ chối nghiệm thu khi sản phẩm thiết kế không đạt yêu cầu về chất lượng.","Đề xuất với chủ đầu tư những bất hợp lý về thiết kế xây dựng."],"answer":2,"explain":""},{"id":201,"cat":"Giám sát thi công","text":"Nội dung nào sau đây không thuộc quyền hạn của nhà thầu giám sát thi công xây dựng công trình?","options":["Tham gia nghiệm thu, xác nhận công việc, công trình đã hoàn thành thi công xây dựng","Tạm dừng thi công trong trường hợp phát hiện công trình có nguy cơ xảy ra mất an toàn hoặc nhà thầu thi công sai thiết kế và thông báo kịp thời cho chủ đầu tư để xử lý;","Yêu cầu nhà thầu thi công xây dựng công trình thực hiện đúng thiết kế được phê duyệt và hợp đồng thi công xây dựng đã ký kết;","Yêu cầu thanh toán giá trị khối lượng xây dựng hoàn thành theo đúng hợp đồng."],"answer":3,"explain":""},{"id":218,"cat":"Giám sát thi công","text":"Chi phí giám sát thi công xây dựng theo quy định được tính như thế nào?","options":["Bằng tỷ lệ % theo quy định nhân với chi phí xây dựng (chưa có thuế giá trị gia tăng) trong dự toán gói thầu xây dựng được duyệt.","Bằng tỷ lệ % theo quy định nhân với chi phí xây dựng (chưa có thuế giá trị gia tăng) trong dự toán công trình xây dựng được duyệt.","Bằng tỷ lệ % theo quy định nhân với chi phí thiết bị (chưa có thuế giá trị gia tăng) trong dự toán gói thầu xây dựng được duyệt.","Bằng tỷ lệ % theo quy định nhân với chi phí thiết bị (chưa có thuế giá trị gia tăng) trong dự toán công trình xây dựng được duyệt."],"answer":0,"explain":""},{"id":219,"cat":"Giám sát thi công","text":"Suất vốn đầu tư xây dựng công trình bao gồm những chi phí nào sau đây:","options":["Chi phí xây dựng, thiết bị (đã bao gồm thuế GTGT).","Chi phí xây dựng, thiết bị, quản lý dự án, tư vấn đầu tư xây dựng và các khoản chi phí khác (chưa bao gồm thuế GTGT cho các chi phí nêu trên).","Chi phí xây dựng; chi phí thiết bị; chi phí quản lý dự án; chi phí tư vấn đầu tư xây dựng; một số khoản mục chi phí khác và thuế giá trị gia tăng cho các chi phí nêu trên.","Chi phí xây dựng, thiết bị, quản lý dự án, tư vấn đầu tư xây dựng, các khoản chi phí khác và chi phí dự phòng (đã bao gồm thuế GTGT cho các chi phí nêu trên)."],"answer":2,"explain":""},{"id":264,"cat":"Giám sát thi công","text":"Nhà thầu tư vấn giám sát thi công xây dựng không có trách nhiệm nào dưới đây?","options":["Thực hiện nghĩa vụ theo nội dung hợp đồng đã được ký kết với chủ đầu tư","Chịu trách nhiệm về chất lượng công việc theo hợp đồng đã được ký kết","Bồi thường thiệt hại khi sử dụng thông tin, tài liệu, tiêu chuẩn, quy chuẩn kỹ thuật, giải pháp kỹ thuật, tổ chức quản lý không phù hợp và vi phạm hợp đồng làm thiệt hại cho chủ đầu tư","Chịu trách nhiệm về chất lượng thiết kế xây dựng công trình"],"answer":3,"explain":""},{"id":265,"cat":"Giám sát thi công","text":"Thiết kế xây dựng đã được phê duyệt chỉ được điều chỉnh khi nào?","options":["Khi điều chỉnh dự án đầu tư xây dựng có yêu cầu điều chỉnh thiết kế xây dựng","Trong quá trình thi công xây dựng có yêu cầu phải điều chỉnh thiết kế xây dựng để bảo đảm chất lượng công trình và hiệu quả của dự án","Bao gồm cả trường hợp a và b","Không được điều chỉnh trong bất kể trường hợp nào"],"answer":2,"explain":""},{"id":266,"cat":"Giám sát thi công","text":"Hồ sơ đề nghị cấp giấy phép xây dựng gồm những tài liệu cơ bản nào?","options":["Đơn đề nghị cấp giấy phép xây dựng","Bản sao một trong những giấy tờ hợp pháp về quyền sử dụng đất","Một số bản vẽ thiết kế xây dựng","Gồm các tài liệu nêu tại a, b và c"],"answer":3,"explain":""},{"id":278,"cat":"Giám sát thi công","text":"Ai có trách nhiệm lập và trình chủ đầu tư chấp thuận kế hoạch tổng hợp về an toàn lao động trước khi khởi công xây dựng công trình?","options":["Ban quản lý dự án đầu tư xây dựng","Nhà thầu thi công xây dựng công trình","Nhà thầu tư vấn giám sát thi công xây dựng công trình","Không có quy định ai phải thực hiện"],"answer":1,"explain":""},{"id":279,"cat":"Giám sát thi công","text":"Theo quy định của pháp luật về xây dựng, kiểm định viên thực hiện kiểm định kỹ thuật an toàn lao động phải được huấn luyện, bồi dưỡng và sát hạch được phân thành mấy nhóm?","options":["Hai","Ba","Bốn","Năm"],"answer":2,"explain":""},{"id":280,"cat":"Giám sát thi công","text":"Trên cơ sở đảm bảo phù hợp trình tự, thủ tục theo quy định của pháp luật về đất đai, việc bồi thường, hỗ trợ, tái định cư được thực hiện tại giai đoạn nào của dự án?","options":["Tại giai đoạn chuẩn bị dự án;","Tại giai đoạn thực hiện dự án;","Đáp án a hoặc đáp án b;","Tại giai đoạn kết thúc xây dựng."],"answer":2,"explain":""},{"id":761,"cat":"Thiết kế đường bộ","text":"Chiều cao của khổ giới hạn trong hầm đường bộ là bao nhiêu?","options":["4750 mm","4800mm","4900mm","5000mm"],"answer":3,"explain":""},{"id":762,"cat":"Thiết kế đường bộ","text":"Tại sao vỏ hầm của đường hầm thi công theo công nghệ NATM thường có chiều dày không đổi?","options":["Nội lực trên các mặt cắt dọc theo chu vi vỏ hầm như nhau.","Vì mục đích để cho đường tim của kết cấu vỏ hầm luôn cùng dạng với đường cong khuôn hầm.","Vì chiều dày vỏ hầm được chọn là nhỏ nhất theo cấu tạo.","Để dễ kiểm soát trong quá trình thi công"],"answer":2,"explain":""},{"id":763,"cat":"Thiết kế đường bộ","text":"Bằng cách nào người ta kiểm soát được thời điểm đưa kết cấu vỏ hầm vào tham gia chịu lực?","options":["Căn cứ vào đường cong Fenner-Pacher.","Căn cứ vào tuổi của bê tông cho phép thời điểm dỡ ván khuôn.","Căn cứ vào độ hội tụ của vách hang thông qua kết quả quan trắc liên tục chuyển vị của vách hang.","Căn cứ vào kinh nghiệm thi công của hàng loạt các công trình"],"answer":2,"explain":""},{"id":764,"cat":"Thiết kế đường bộ","text":"Neo đá (Rock bolt) khác neo đất (Ground anchor) ở điểm nào?","options":["Neo đá dùng để chống đỡ hang đào, neo đất dùng để gia cố chống vách.","Neo đá có hiệu ứng tạo dầm và cài khóa còn neo đất thì không.","Không có sự phân biệt dùng trong đá gọi là neo đá, dùng trong đất gọi là neo đất.","Neo đá bố trí vuông góc với bề mặt gia cố còn neo đất bố trí xiên góc với bề mặt."],"answer":1,"explain":""},{"id":765,"cat":"Thiết kế đường bộ","text":"Tác dụng của neo dự ứng lực sử dụng trong xây dựng đường hầm.","options":["Tương tự như thanh neo là treo giữ khối lở rời nhưng sử dụng được thép cường độ cao.","Tăng khả năng chống trượt cho khối lăng thể trượt","Dễ thực hiện trong không gian có kích thước hạn chế.","Sử dụng vật tư phổ biến dễ khai thác đó là cáp tao xoắn 7 sợi"],"answer":1,"explain":""},{"id":766,"cat":"Thiết kế đường bộ","text":"Để phân loại một khu vực cấu trúc địa chất nào đó theo RMR (Rock Macc Rating) người ta phải khảo sát bao nhiêu loại thông số địa chất?","options":["5","6","7","8"],"answer":1,"explain":""},{"id":767,"cat":"Thiết kế đường bộ","text":"Hệ số kiên cố theo Prô-tô-đia- cô- nốp fkp được sử dụng trong ngành xây dựng đường hầm như thế nào?","options":["Chỉ sử dụng trong phương pháp mỏ truyền thống.","Sử dụng để chọn vị trí cửa hầm và khoảng cách giữa hai hầm đơn song song.","Chỉ sử dụng trong Tiêu chuẩn thiết kế TCVN4527-88.","Khi công nghệ thi công NATM trở thành phổ biến không nên quan tâm đến khái niệm này nữa."],"answer":1,"explain":""},{"id":768,"cat":"Thiết kế đường bộ","text":"Vì sao các tính toán trong thiết kế đường hầm thi công theo công nghệ NATM lại dựa trên phương pháp phân loại địa chất RMR?","options":["Phương pháp RMR cung cấp biểu đồ Bienniawcki quan hệ giữa RMR và thời gian tự đứng vững.","Do thông qua chỉ số RMR có thể tính được áp lực pa tác dụng lên kết cấu chống đỡ.","Phương pháp RMR chỉ dẫn cách chọn chiều dày lớp bê tông phun và khoảng cách neo.","Phương pháp RMR cung cấp cách chọn sơ bộ chiều dày lớp bê tông vỏ hầm."],"answer":0,"explain":""},{"id":769,"cat":"Thiết kế đường bộ","text":"Công cụ dùng để biểu diễn hệ thống khe nứt của khối đá trong báo cáo khảo sát địa chất công trình khu vực đường hầm là gì?","options":["Đồ thị hoa hồng","Đồ thị Xavarenxki","Đồ thị vòng tròn lớn","Một trong ba loại trên"],"answer":3,"explain":""},{"id":770,"cat":"Thiết kế đường bộ","text":"Vì sao nói chỉ số RQD được sử dụng phổ biến trong nghiên cứu địa chất của khối đá?","options":["Vì RQD đặc trưng cho tính chất nứt nẻ của khối đá.","Vì thông qua RQD để đánh giá độ bền của khối đá.","Vì sử dụng RQD để phân loại địa chất khối đá.","Vì người ta sử dụng chỉ số này trong hầu hết các phương pháp phân loại địa chất khối đá."],"answer":3,"explain":""},{"id":771,"cat":"Thiết kế đường bộ","text":"Đường cong Fenner-Pacher phản ánh mối quan hệ nào sau đây?","options":["Giữa áp lực lên biên hạng và chuyển vị vách hang đào.","Giữa tỉ lệ áp lực sau giải phóng ứng suất tác dụng lên kết cấu chống đỡ và chuyển vị vách hang đào.","Giữa áp lực tác dụng lên kết cấu chống đỡ và chuyển vị vách hang đào.","Giữa áp lực tác dụng lên kết cấu và biến dạng tương đối của vách hang đào"],"answer":1,"explain":""},{"id":772,"cat":"Thiết kế đường bộ","text":"Hãy cho biết biện pháp xác định áp lực từ biên hạng tác dụng lên kết cấu chống đỡ trong thiết kế đường hầm thi công theo công nghệ NATM.","options":["Từ công thức của Fenner-Labasse.","Từ công thức thực nghiệm của phương pháp phân loại địa chất RMR.","Từ đường cong Fenner-Pacher","Từ đường cong quan hệ Pa-U."],"answer":3,"explain":""},{"id":773,"cat":"Thiết kế đường bộ","text":"Hãy cho biết tải trọng do đất đá tác dụng lên kết cấu vỏ hầm bê tông theo quan điểm của phương pháp công nghệ NATM.","options":["Tải trọng này bằng không vì đã do kết cấu neo và bê tông phun chịu hết tác dụng của đất đá xung quanh hang đào.","Tải trọng này bằng không vì áp lực hướng tâm tại bề mặt vách hang đào luôn bằng không.","Tải trọng này bằng không vì đã giải phóng hết để cho vành đất đá mang tải xung quanh hang đào chịu.","Là phần còn lại của áp lực hướng tâm tác dụng lên biên hạng sau giải phóng ứng suất"],"answer":3,"explain":""},{"id":774,"cat":"Thiết kế đường bộ","text":"Trong điều kiện địa chất bình thường, chiều dày của lớp bê tông vỏ hầm thi công theo phương pháp công nghệ NATM được lựa chọn dựa trên căn cứ nào?","options":["Theo yêu cầu cấu tạo","Theo yêu cầu chịu lực","Theo cấu tạo, có kiểm toán đảm bảo yêu cầu chịu lực.","Theo công thức kinh nghiệm"],"answer":2,"explain":""},{"id":775,"cat":"Thiết kế đường bộ","text":"Rãnh dọc trong đường hầm xuyên núi có sử dụng lớp chống thấm được bố trí để thoát nước ngầm hay thoát nước mặt?","options":["Thoát nước ngầm là chính.","Thoát nước mặt là chính vì nước ngầm đã được chống thấm.","Đồng thời thoát cả nước ngầm và nước mặt.","Có hai hệ thống rãnh dọc riêng cho thoát nước ngầm và cho nước mặt."],"answer":3,"explain":""},{"id":776,"cat":"Thiết kế đường bộ","text":"Hãy phân biệt hai khái niệm khổ giới hạn trong đường hầm và tĩnh không hầm.","options":["Là một khái niệm, khác nhau về cách gọi tên.","Là hai khái niệm khác nhau.","Tĩnh không là những kích thước chính của khổ giới hạn.","Tĩnh không trong hầm là khổ giới hạn trên đường cộng với những khoảng mở rộng cần thiết"],"answer":3,"explain":""},{"id":777,"cat":"Thiết kế đường bộ","text":"Kết cấu vỏ hầm của đường hầm xuyên núi có bao nhiêu dạng mặt cắt?","options":["4","5","6","7"],"answer":2,"explain":""},{"id":778,"cat":"Thiết kế đường bộ","text":"Một bước quan trọng trong trong thiết kế đường hầm là xây dựng đường khuôn hầm. Hãy cho biết khuôn hầm là gì?","options":["Là ván khuôn của vỏ hầm.","Là tĩnh không trong hầm.","Là đường cong viền kín bề mặt bên trong của vỏ hầm","Là khổ giới hạn trong đường hầm"],"answer":2,"explain":""},{"id":779,"cat":"Thiết kế đường bộ","text":"Vỏ hầm đường bộ hình móng ngựa được xây dựng từ loại đường cong nào sau đây?","options":["Nửa đường tròn phần vòm và hai đoạn tường thẳng.","Đường cong 3 tâm.","Đường cong 5 tâm","Quá nửa đường tròn bán kính R"],"answer":3,"explain":""},{"id":780,"cat":"Thiết kế đường bộ","text":"Khoảng cách lề dừng đỗ khẩn cấp trong hầm đường bộ là bao nhiêu mét khi có hai hầm đơn chạy song song nhau.","options":["500m","600m","700m","750m"],"answer":1,"explain":""},{"id":781,"cat":"Thiết kế đường bộ","text":"Đoạn mở rộng của đường hầm có lề dừng đỗ khẩn cấp được vuốt nối với đoạn không mở rộng như thế nào?","options":["Mở giật cấp 90°","Mở rộng dần trên chiều dài đoạn chuyển tiếp 10m.","Mở rộng dần trên đoạn chuyển tiếp 12m.","Mở rộng dần trên đoạn chuyển tiếp 15m"],"answer":0,"explain":""},{"id":782,"cat":"Thiết kế đường bộ","text":"Để đảm bảo cường độ và độ ổn định của nền đường cần quan tâm đến vùng hoạt động 80 cm từ đáy áo đường: 30 cm trên phải đảm bảo CBR bằng 8 với đường cấp I, II và bằng 6 với các cấp khác. 50 cm tiếp với CBR bằng 5 với đường cấp I, II và bằng 4 với các cấp khác. Trị số CBR được xác định trong trường hợp nào ?","options":["CBR xác định trong trường hợp lấy mẫu tự nhiên","CBR xác định ngoài hiện trường","CBR xác định trong phòng, mẫu đất được đầm nén tiêu chuẩn, để khô.","CBR xác định trong phòng, mẫu đất được đầm nén tiêu chuẩn và ngâm mẫu 4 ngày đêm."],"answer":3,"explain":""},{"id":783,"cat":"Thiết kế đường bộ","text":"Trong thiết kế mặt đường bê tông xi măng theo Quyết định 32-30 của Bộ giao thông vận tải thì cần kiểm tra cường độ kéo uốn của tấm bê tông xi măng khi tải trọng bánh xe đặt ở đâu ?","options":["Tải trọng xe đặt giữa tấm","Tải trọng xe đặt ở góc tấm","Tải trọng xe đặt ở giữa cạnh dài của tấm","Phải kiểm tra cả 3 vị trí trên"],"answer":2,"explain":""},{"id":784,"cat":"Thiết kế đường bộ","text":"Trong thiết kế mặt đường bê tông xi măng theo quy trình thiết kế áo đường cứng 22TCN223-95 cần kiểm tra chiều dày của tấm bê tông xi măng khi tải trọng bánh xe đặt ở đâu ?","options":["Tải trọng xe đặt giữa tấm","Tải trọng xe đặt ở góc tấm","Tải trọng xe đặt ở giữa cạnh dài của tấm","Phải kiểm tra cả 3 vị trí trên chọn chiều dày lớn nhất"],"answer":3,"explain":""},{"id":785,"cat":"Thiết kế đường bộ","text":"Kiểm toán kết cấu áo đường mềm đối với mặt đường cấp cao A1 phải kiểm toán theo các thái giới hạn nào ?","options":["Kiểm toán cường độ chung kết cấu.","Kiểm toán cắt trượt nền đất","Kiểm toán ứng suất kéo uốn của lớp mặt bê tông nhựa","Kiểm toán tất cả trạng thái giới hạn nêu trên"],"answer":3,"explain":""},{"id":786,"cat":"Thiết kế đường bộ","text":"Khi thiết kế mặt đường bê tông nhựa, phải kiểm tra cường độ kéo uốn lớp bê tông nhựa, vị trí kiểm tra là đâu trong các phương án sau ?","options":["Kiểm tra tại mặt trên lớp bê tông nhựa","Kiểm tra tại vị trí giữa lớp bê tông nhựa","Kiểm tra tại vị trí 2/3 từ mặt bê tông nhựa","Kiểm tra tại vị trí đáy lớp bê tông nhựa"],"answer":3,"explain":""},{"id":787,"cat":"Thiết kế đường bộ","text":"Nhằm đảm bảo sự chuyển tiếp êm thuận, không gây ra “xóc” mạnh cho xe chạy qua đoạn chuyển tiếp thì độ bằng phẳng theo dọc tim đường S (S là độ dốc dọc giữa hai điểm trên mặt đường theo phương dọc theo tim đường do sự chênh lệch lún của hai điểm đó) giữa đường và cầu đối với đường cao tốc có vận tốc thiết kế 100 và 120 km/h là bao nhiêu trong các giá trị sau ?","options":["Độ bằng phẳng S ≤ 1/150","Độ bằng phẳng S ≤ 1/175","Độ bằng phẳng S ≤ 1/200","Độ bằng phẳng S ≤ 1/250"],"answer":3,"explain":""},{"id":789,"cat":"Thiết kế đường bộ","text":"Khi xác định lưu lượng xe tính toán để xác định Eyc mặt đường phải xét đến hệ số ảnh hưởng của số làn xe. Trong trường hợp đường có 4 làn xe có dải phân cách giữa thì hệ số phân phối trục xe f chọn là bao nhiêu ?","options":["Hệ số f = 1","Hệ số f = 0,55","Hệ số f= 0,35","Hệ số f = 0,3"],"answer":2,"explain":""},{"id":791,"cat":"Thiết kế đường bộ","text":"Tốc độ cho phép lưu hành trên đường là phương án nào trong phương án sau ?","options":["Là tốc độ thiết kế của đường","Là tốc độ quy định theo cấp hạng kỹ thuật của đường","Là tốc độ tối thiểu xe chạy trên đường","Là tốc độ lưu hành cho phép phụ thuộc vào tình trạng thực tế của đường do cơ quan quản lý đường quy định"],"answer":3,"explain":""},{"id":792,"cat":"Thiết kế đường bộ","text":"Khi thiết kế trắc dọc đường ô tô cao tốc TCVN 5729: 2012 quy định chiều dài tối thiểu tùy thuộc vào cấp đường và phải đủ để bố trí chiều dài đường cong đứng. Với đường cấp 100 (Vtk = 100 km/h) chiều dài tối thiểu là bao nhiêu ?","options":["Chiều dài tối thiểu 300 mét","Chiều dài tối thiểu 250 mét","Chiều dài tối thiểu 200 mét","Chiều dài tối thiểu 150 mét"],"answer":1,"explain":""},{"id":794,"cat":"Thiết kế đường bộ","text":"Độ bằng phẳng của mặt đường có thể dùng thước 3 mét để kiểm tra. Đối với mặt đường cấp cao A1 (bê tông nhựa, bê tông xi năng) thì quy định nào đúng trong các phương án sau:","options":["70% số khe hở dưới 3mm và 30% số khe hở phải dưới 5 mm.","20% số khe hở dưới 3mm và 80% số khe hở phải dưới 5 mm.","30% số khe hở dưới 3mm và 70% số khe hở phải dưới 5 mm","40% số khe hở dưới 3mm và 60% số khe hở phải dưới 5 mm"],"answer":0,"explain":""},{"id":795,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường quy định cao độ thiết kế nền đường. Quy định nào trong 4 trường hợp sau đây là đúng và đủ?","options":["Cao độ thiết kế của nền đường là cao độ ở tim đường.","Cao độ thiết kế của nền đường là cao độ ở tim đường. Khi có hai nền đường độc lập sẽ có hai cao độ thiết kế trên hai mặt cắt dọc riêng biệt.","Cao độ thiết kế của nền đường là cao độ vai đường","Cao độ thiết kế của nền đường là cao độ mép mặt đường"],"answer":1,"explain":""},{"id":796,"cat":"Thiết kế đường bộ","text":"Khi thiết kế rãnh biên qua khu dân cư chọn phương án nào là hợp lý?","options":["Rãnh đất hoặc rãnh xây hình thang.","Rãnh đất hoặc rãnh xây hình tam giác.","Rãnh bê tông nửa tròn.","Rãnh xây hoặc bê tông xi măng có lát các tấm đan che kín, có hệ thống thu nước mưa."],"answer":3,"explain":""},{"id":798,"cat":"Thiết kế đường bộ","text":"Cường độ kết cấu áo đường mềm được đặc trưng bởi giá trị nào trong các phương án sau?","options":["Mô đun đàn hồi của các lớp mặt đường.","Mô đun đàn hồi của các lớp móng đường.","Mô đun đàn hồi của lớp nền đất dưới kết cấu áo đường.","Mô đun đàn hồi chung của các lớp trong kết cấu áo đường + nền đất"],"answer":3,"explain":""},{"id":799,"cat":"Thiết kế đường bộ","text":"Khi thiết kế đường cao tốc ở vùng địa hình núi, đồi cao và vùng địa hình khó khăn người ta quy định chọn vận tốc hợp lý để giảm kinh phí xây dựng. Trong các phương án sau chọn phương án nào là hợp lý.","options":["Tốc độ thiết kế 100- 120 km/h","Tốc độ thiết kế 80- 100 km/h","Tốc độ thiết kế 60- 80 km/h","Tốc độ thiết kế 50 - 60 km/h"],"answer":2,"explain":""},{"id":800,"cat":"Thiết kế đường bộ","text":"Khi thiết kế đường cao tốc ở vùng đồng bằng. Trong các phương án sau chọn phương án nào là đúng với quy định tiêu chuẩn.","options":["Tốc độ thiết kế 120- 130 km/h","Tốc độ thiết kế 100- 120 km/h","Tốc độ thiết kế 80- 100 km/h","Tốc độ thiết kế 60- 80 km/h"],"answer":1,"explain":""},{"id":801,"cat":"Thiết kế đường bộ","text":"Khi thiết kế đường ô tô cao tốc để đảm bảo an toàn chạy xe, người ta quy định chiều dài tối đa các đoạn thẳng. Các phương án sau phương án nào đúng?","options":["Chiều dài tối đa 10 km.","Chiều dài tối đa 6 km.","Chiều dài tối đa 4 km","Chiều dài tối đa 2 km"],"answer":2,"explain":""},{"id":802,"cat":"Thiết kế đường bộ","text":"Về mặt cấu tạo nút giao thông cùng mức ngoài đô thị, theo TCVN405 - 2005 chia làm mấy loại?","options":["1 loại","2 loại","3 loại","4 loại"],"answer":2,"explain":""},{"id":803,"cat":"Thiết kế đường bộ","text":"Trong các đường cong bằng bán kính nhỏ phải bố trí siêu cao, độ dốc siêu cao phụ thuộc vào vận tốc thiết kế và bán kính đường cong. Tiêu chuẩn thiết kế quy định độ dốc tối đa và độ dốc tối thiểu. Các phương án sau phương án nào đúng với quy định?","options":["Đội dốc siêu cao tối đa 10%, tối thiểu 2%","Đội dốc siêu cao tối đa 8%, tối thiểu 2%","Đội dốc siêu cao tối đa 6%, tối thiểu 2%","Đội dốc siêu cao tối đa 4%, tối thiểu 2%"],"answer":1,"explain":""},{"id":804,"cat":"Thiết kế đường bộ","text":"Trên các tuyến đường có bố trí các tuyến xe buýt, để đảm bảo an toàn tiêu chuẩn thiết kế quy định có thể sử dụng loại chỗ dừng đơn giản hoặc chỗ dừng cách ly. Với các phương án sau, phương án nào đúng?","options":["Trên đường Vtk ≥40 km/h, nhất thiết phải thiết kế chỗ dừng cách ly.","Trên đường Vtk ≥60 km/h, nhất thiết phải thiết kế chỗ dừng cách ly.","Trên đường Vtk ≥80 km/h, nhất thiết phải thiết kế chỗ dừng cách ly","Trên đường Vtk ≥100 km/h, nhất thiết phải thiết kế chỗ dừng cách ly"],"answer":2,"explain":""},{"id":805,"cat":"Thiết kế đường bộ","text":"Khi thiết kế một tuyến đường ô tô, tiêu chuẩn quy định chiều dài tối thiểu thống nhất theo một cấp để đảm bảo an toàn. Đường từ cấp III trở lên chiều dài tối thiểu quy định là bao nhiêu trong các phương án sau?","options":["Chiều dài tối thiểu 5 km.","Chiều dài tối thiểu 10 km.","Chiều dài tối thiểu 15 km.","Chiều dài tối thiểu 20 km"],"answer":1,"explain":""},{"id":806,"cat":"Thiết kế đường bộ","text":"Biển báo hiệu đường bộ theo QCVN41-2016 được phân thành mấy nhóm? Các phương án sau phương án nào đúng?","options":["Có 3 nhóm biển báo hiệu đường bộ.","Có 4 nhóm biển báo hiệu đường bộ.","Có 5 nhóm biển báo hiệu đường bộ.","Có 6 nhóm biển báo hiệu đường bộ"],"answer":2,"explain":""},{"id":807,"cat":"Thiết kế đường bộ","text":"Khi thiết kế mặt đường cho đường phố và đường ít quan trọng ở đô thị thì dùng tải trọng trục nào để tính toán trong các phương án sau?","options":["Tải trọng trục 12.000 daN","Tải trọng trục 10.000 daN","Tải trọng trục 9.500 daN","Tải trọng trục 8.000 daN"],"answer":2,"explain":""},{"id":808,"cat":"Thiết kế đường bộ","text":"Khi thiết kế mặt đường cho đường trục chính đô thị thì dùng tải trọng nào để tính toán trong các phương án sau?","options":["Tải trọng trục 12.000 daN","Tải trọng trục 10.000 daN","Tải trọng trục 9.500 daN","Tải trọng trục 8.000 daN"],"answer":0,"explain":""},{"id":809,"cat":"Thiết kế đường bộ","text":"Độ bằng phẳng mặt đường được đánh giá qua chỉ số độ gồ ghề quốc tế IRI (m/km). Với đường vận tốc thiết kế Vtk = 100 -120 km/h, làm mới thì IRI yêu cầu phải là phương án nào trong số phương án sau?","options":["Chỉ số IRl yêu cầu ≤ 2,0","Chỉ số IRI yêu cầu ≤ 2,2","Chỉ số IRI yêu cầu ≤ 2,5","Chỉ số IRI yêu cầu ≤ 4,0"],"answer":0,"explain":""},{"id":814,"cat":"Thiết kế đường bộ","text":"Khi đắp nền đường trên đất yếu phải sử dụng lớp đệm cát để thoát nước ngang. Trong các trường hợp sau trường hợp nào phải dùng tầng đệm cát:","options":["Trường hợp đắp trực tiếp trên đất yêu","Trường hợp đào một phần hay toàn bộ tầng đất yếu","Sử dụng giếng cát hay bấc thấm thoát nước thẳng đứng","Tất cả 3 trường hợp trên"],"answer":3,"explain":""},{"id":815,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường ô tô TCVN 4054 - 2005 ngoài đường ô tô cao tốc, có các phương án phân loại dưới đây. Phương án nào đúng.","options":["Đường có 6 cấp, từ cấp I tới cấp VI","Đường có 5 cấp, từ cấp I tới cấp V","Đường có 4 cấp, từ cấp I tới cấp IV","Đường có 3 cấp, từ cấp I tới cấp III"],"answer":0,"explain":""},{"id":816,"cat":"Thiết kế đường bộ","text":"Theo tiêu chuẩn thiết kế đường giao thông nông thôn TCVN 0380: 2014 đường giao thông nông thôn có mấy cấp? chọn phương án đúng?","options":["Có 1 cấp A","Có 2 cấp A, B","Có 3 cấp A, B, C","Có 4 cấp A, B, C, D"],"answer":3,"explain":""},{"id":817,"cat":"Thiết kế đường bộ","text":"Tốc độ thiết kế của đường được hiểu thế nào?","options":["Tốc độ lớn nhất cho phép xe chạy trên đường","Tốc độ khai thác của đường","Là tốc độ được dùng để tính toán các chỉ tiêu kỹ thuật chủ yếu của đường trong trường hợp khó khăn","Tốc độ trung bình xe chạy trên đường"],"answer":2,"explain":""},{"id":818,"cat":"Thiết kế đường bộ","text":"Chiều rộng một làn xe trong tiêu chuẩn thiết kế đường TCVN 4054 - 2005 có mấy loại kích thước? Phương án nào đúng và đủ?","options":["Có các chiều rộng 3,75 m, 3,5 mét, 3,0 m và 2,75 m.","Có các chiều rộng 3,75 m, 3,5 mét và 3,0 m.","Có các chiều rộng 3,75 m, 3,5 mét","Chỉ có chiều rộng 3,5 m"],"answer":0,"explain":""},{"id":819,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế yếu tố hình học của đường quy định mấy loại bán kính đường cong nằm tối thiểu? phương án nào đúng và đủ.","options":["Bán kính đường cong nằm tối thiểu giới hạn","Bán kính đường đường cong tối thiểu giới hạn, tối thiểu thông thường","Bán kính đường cong tối thiểu giới hạn, tối thiểu không siêu cao","Bán kính tối thiểu giới hạn, tối thiểu thông thường và tối thiểu không siêu cao"],"answer":3,"explain":""},{"id":821,"cat":"Thiết kế đường bộ","text":"Trong thiết kế đường việc phối hợp giữa các yếu tố tuyến nhằm mục đích gì","options":["Tạo tầm nhìn tốt, cung cấp thông tin cho người lái xe để kịp thời xử trí các tình huống.","Tạo tâm lý thoải mái cho người lái, ít mệt nhọc, năng suất cao.","Tạo cho công trình phù hợp với cảnh quan, góp phần nâng cao vẻ đẹp khu vực đặt tuyến.","Để đạt tất cả mục đích nêu trên"],"answer":3,"explain":""},{"id":822,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường quy định độ dốc dọc lớn nhất tùy thuộc vào cấp hạng đường và điều kiện địa hình. Trường hợp đường cấp I đồng bằng thì độ dốc dọc lớn nhất là bao nhiêu?","options":["Độ dốc dọc lớn nhất 3%","Độ dốc dọc lớn nhất 4%","Độ dốc dọc lớn nhất 5%","Độ dốc dọc lớn nhất 6%"],"answer":0,"explain":""},{"id":824,"cat":"Thiết kế đường bộ","text":"Quy định về hệ số đầm chặt đất nền đường phụ thuộc vào các yếu tố nào?","options":["Phụ thuộc vào nền đường đào, đắp","Phụ thuộc vào cấp hạng kỹ thuật của đường","Phụ thuộc vào chiều sâu từ đáy áo đường xuống","Phụ thuộc vào cả 3 yếu tố trên"],"answer":3,"explain":""},{"id":825,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường đô thị TCXDVN104: 2007 phân loại đường phố trong đô thị thành mấy loại.?","options":["Có 4 loại đường đô thị","Có 3 loại đường đô thị","Có 2 loại đường đô thị","Có 1 loại đường đô thị"],"answer":0,"explain":""},{"id":827,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường TCVN 4054 - 2005, lưu lượng thiết kế là lưu lượng xe con được quy đổi từ các loại xe khác, thông qua mặt cắt trong ngày đêm, tính cho năm tương lai. Với đường cấp I, II, năm tương lai quy định là năm nào trong các phương án sau?","options":["Năm thứ 10","Năm thứ 15","Năm thứ 20","Năm thứ 25"],"answer":2,"explain":""},{"id":830,"cat":"Thiết kế đường bộ","text":"Độ dốc ngang của mặt đường trên các đoạn thẳng được quy định để đảm bảo thoát nước mưa, phụ thuộc vào loại mặt đường. Với mặt đường bê tông xi măng và bê tông nhựa chọn độ dốc ngang bao nhiêu là đúng?","options":["Độ dốc ngang 1,5 - 2,0 %","Độ dốc ngang 1,5 - 3,0 %","Độ dốc ngang 2,0 - 3,0 %","Độ dốc ngang 3,0 - 4,0 %"],"answer":0,"explain":""},{"id":831,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế đường TCVN 4054 - 2005 quy định: H là chiều cao tĩnh không, tính từ điểm cao nhất của phần xe chạy chưa xét đến chiều cao dự trữ nâng cao mặt đường khi sửa chữa, cải tạo, nâng cấp); h chiều cao tĩnh không ở mép ngoài lề đường. Khi thiết kế đường cấp I, II, III chọn các giá trị nào trong các phương án sau:","options":["H = 5,0, h = 4,5m","H = 4,75, h = 4,0 m","H = 4,5 , h = 4,0 m","H = 4,25, h = 4,0 m"],"answer":1,"explain":""},{"id":833,"cat":"Thiết kế đường bộ","text":"Trong tiêu chuẩn thiết kế mặt đường, phân ra mấy loại tầng mặt đường (cấp mặt đường)?","options":["Chỉ có 1 loại tầng mặt đường","Có 2 loại tầng mặt đường","Có 3 loại tầng mặt đường","Có 4 loại tầng mặt đường"],"answer":3,"explain":""},{"id":834,"cat":"Thiết kế đường bộ","text":"Tải trọng tính toán mặt đường mềm, đối với đường ngoài đô thị được quy định tải trọng trục xe. Tải trọng quy định là bao nhiêu?","options":["Tải trọng trục 12 KN","Tải trọng trục 14 KN","Tải trọng trục 10KN","Tải trọng trục 8 KN"],"answer":2,"explain":""},{"id":835,"cat":"Thiết kế đường bộ","text":"Tải trọng tính toán mặt đường cứng, đối với đường ngoài đô thị được quy định tải trọng trục xe. Tải trọng quy định là bao nhiêu?","options":["Tải trọng trục 12 KN","Tải trọng trục 14 KN","Tải trọng trục 10KN","Tải trọng trục 8 KN"],"answer":2,"explain":""},{"id":836,"cat":"Thiết kế đường bộ","text":"Khi khảo sát đường phải đo cao tổng quát để tính cao độ các mốc, sai số giữa hai lần đo fh = a., trong đó fh tính bằng mm, L khoảng cách giữa hai mốc tính bằng Km; a. giá trị cho dưới đây. Trong các phương án đưa ra chọn phương án đúng.","options":["fh = 20.","fh = 30.","fh = 40.","fh = 40."],"answer":1,"explain":""},{"id":837,"cat":"Thiết kế đường bộ","text":"Khi khảo sát đường phải đo cao chi tiết các cọc để khớp với cao độ các mốc, sai số giữa hai lần đo fh = a.  trong đó fh tính bằng mm, L khoảng cách giữa hai mốc tính bằng Km; a. giá trị cho dưới đây. Trong các phương án đưa ra chọn phương án đúng.","options":["fh = 20. L","fh = 30. L","fh = 40. L","fh = 50. L"],"answer":3,"explain":""},{"id":838,"cat":"Thiết kế đường bộ","text":"Khi khảo sát lập thiết kế kỹ thuật tuyến đường, quy định phải đo dài tổng quát để đóng các cọc H, cọc Km, quy định sai số cho phép hai lần đo fl = 1/ a. L,. fl sai số tính bằng mét, L chiều dài đo tính bằng mét, a giá trị cho dưới đây. Trong các phương án đưa ra chọn phương án đúng.","options":["fl = 1/100. L","fl = 1/500. L","fl = 1/1000. L","fl = 1/1500. L"],"answer":2,"explain":""},{"id":840,"cat":"Thiết kế cầu hầm","text":"Để xác định hiệu ứng do tải trọng thường xuyên DC tác dụng lên cầu dầm liên tục thi công theo phương pháp đúc hẫng cân bằng ta chất tải trọng này lên sơ đồ tính toán nào của kết cấu nhịp ?","options":["Sơ đồ dầm liên tục.","Sơ đồ dầm giản đơn mút thừa.","Sơ đồ đúc hẫng cân bằng.","Sơ đồ kết cấu nhịp trước khi thực hiện đốt hợp long cuối cùng"],"answer":3,"explain":""},{"id":841,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết cách tính hệ số phân bố ngang của cầu dầm và cầu bản đặt chéo một góc θ so với dòng chảy ? 3. Tính như cầu đặt thẳng nhưng khoảng cách s giữa các dầm lấy bằng s/cosθ.","options":["Tính như đối với cầu đặt thẳng sau đó nhân với hệ số điều chỉnh c1.","Tính như đối với cầu thẳng sau đó nhân với hệ số điều chỉnh tgθ/c1.","Tính như đối với cầu thẳng sau đó nhân với hệ số điều chỉnh 1- c1(tgθ)3/2"],"answer":2,"explain":""},{"id":842,"cat":"Thiết kế cầu hầm","text":"Hãy giải thích tại sao tỉ lệ giữa chiều dài nhịp biên và chiều dài nhịp chính trong cầu dầm liên tục thi công theo công nghệ đúc hẫng cân bằng lại không lấy theo tỉ lệ hợp lý đối với dầm liên tục là 0,8 ?","options":["Để giảm chiều dài đoạn dầm đúc trên đà giáo cố định.","Để giảm phản lực gối lên mố hoặc trụ biên.","Để không xuất hiện mô men âm ở mặt cắt giữa nhịp chính.","Để sơ đồ làm việc của kết cấu nhịp gần với sơ đồ đúc hẫng."],"answer":2,"explain":""},{"id":843,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết sơ đồ được áp dụng để phân tích nội lực hộp dầm cầu bê tông thi công phân đoạn làm việc theo phương ngang cầu ?","options":["Tính theo sơ đồ bản kê hai cạnh.","Tính theo sơ đồ dầm liên tục.","Tính theo sơ đồ khung kín.","Tính theo sơ đồ bản kê bốn cạnh."],"answer":2,"explain":""},{"id":844,"cat":"Thiết kế cầu hầm","text":"Xét ảnh hưởng của các tải trọng thi công đến nội lực tính toán của các dạng kết cấu nhịp cầu thi công theo phương pháp phân đoạn như thế nào ?","options":["Chỉ xét đối với sơ đồ kết cấu nhịp trong giai đoạn thi công, không xét trong giai đoạn khai thác.","Cộng tác dụng giai đoạn có sơ đồ thi công bất lợi nhất với hiệu ứng dỡ tải khi rút tải trọng thi công khỏi kết cấu nhịp.","Không ảnh hưởng đến nội lực tính toán vì tải trọng thi công chỉ xuất hiện tạm thời.","Xét với sơ đồ kết cấu nhịp trong giai đoạn thi công để kiểm tra, không cộng với hiệu ứng dỡ tải."],"answer":1,"explain":""},{"id":845,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết nguyên lý của phương pháp địa chấn (Seismic Method) để thăm dò địa chất công trình trong khảo sát xây dựng đường hầm?","options":["Tạo chấn động tại một điểm và đo thời gian truyền sóng tới các đầu thu (geophon) đặt trên mặt đất.","Tạo chấn động tại một điểm và đo thời gian truyền sóng tới các đầu thu đặt dọc theo chiều sâu lỗ khoan xuyên qua các địa tầng.","Tạo chấn động tại nhiều điểm dọc theo chiều sâu lỗ khoan xuyên qua các địa tầng và đo thời gian truyền sóng tới các đầu thu đặt ở những điểm tương ứng trong một lỗ khoan khác.","Một trong ba biện pháp nêu trên"],"answer":3,"explain":""},{"id":846,"cat":"Thiết kế cầu hầm","text":"Sự khác nhau giữa các loại neo đá sử dụng để chống đỡ đường hang trong đường hầm thi công theo phương pháp mỏ truyền thống và đường hầm thi công theo phương pháp công nghệ NATM?","options":["Khác nhau về cấu tạo.","Khác nhau về sơ đồ làm việc.","Khác nhau về tuổi thọ.","Khác nhau về vai trò của kết cấu."],"answer":3,"explain":""},{"id":847,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết ý nghĩa thực tế các lời giải của Kirsch phương trình trạng thái ứng suất biến dạng của nền đất xung quanh hang đào trong môi trường liên tục đàn hồi?","options":["Dùng để tính các ứng suất tác dụng lên kết cấu chống đỡ của đường hầm.","Dùng để tính chuyển vị của hang đào.","Dùng để tính các ứng suất chính trong đánh giá độ bền theo tiêu chuẩn Mohr-Coulomb hoặc Hoek-Brown.","Dùng đề tính toán độ ổn định của hang đào"],"answer":2,"explain":""},{"id":848,"cat":"Thiết kế cầu hầm","text":"Tại sao trong công nghệ NATM lớp bê tông phun được yêu cầu phải mỏng và mềm?","options":["Để thi công được nhanh chóng, kịp thời chống rơi lở cho vách hang.","Lớp bê tông phun này chỉ là một lớp trát nên không cần dày để tiết kiệm chi phí.","Để lớp này chuyển vị cùng với vách hang.","Vì công nghệ phun không thể đắp dày được"],"answer":2,"explain":""},{"id":849,"cat":"Thiết kế cầu hầm","text":"Xét tác dụng của lực căng các dây văng lên sự phân bố nội lực trong các bộ phận của kết cấu nhịp cầu dây văng như thế nào?","options":["Đặt lực căng dây tại các nút liên kết dầm-dây của sơ đồ hoàn chỉnh.","Lần lượt thay từng đôi dây bằng các lực căng vào sơ đồ hoàn chỉnh, sau đó cộng tác dụng.","Lần lượt thay từng nhánh dây bằng lực căng vào sơ đồ hoàn chỉnh, sau đó cộng tác dụng.","Tính theo trình tự lắp dây, thay từng nhánh dây bằng lực căng, sau đó cộng tác dụng."],"answer":3,"explain":""},{"id":850,"cat":"Thiết kế cầu hầm","text":"Ứng suất kéo khống chế tại các mối nối giữa các đốt đúc trong giai đoạn thi công đúc hẫng là giá trị nào sau đây?","options":["Không cho xuất hiện ứng suất kéo.","0,63","0,5","0,25"],"answer":3,"explain":""},{"id":851,"cat":"Thiết kế cầu hầm","text":"Lực nâng (hoặc ép xuống) của gió tác dụng lên cánh hẫng của dầm đúc hẫng trong giai đoạn thi công được tính như thế nào?","options":["1,25 kN/m2 x diện tích mặt cầu x sin 10°.","0,5 kN/m2 x diện tích mặt cầu x sin 10°.","2,4 x10-4 Mpa x diện tích mặt cầu.","Tính theo tải trọng gió đứng điều 3.8.2 (22TCN-272-05)"],"answer":2,"explain":""},{"id":852,"cat":"Thiết kế cầu hầm","text":"Khoảng cách giữa hai tim hầm đơn song song được xác định theo công thức: Khoảng cách nhằm này đáp ứng yêu cầu gì?","options":["Đảm bảo khả năng chịu lực của khối đất nằm giữa hai hầm.","Đảm bảo an toàn nổ mìn khi hai đường hầm cùng thi công.","Đảm bảo khi khoan cắm neo các neo không giao cắt nhau.","Đảm bảo không gian ngoài hai cửa hầm đủ rộng để bố trí vòng quay đầu xe"],"answer":0,"explain":""},{"id":853,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết ý nghĩa cơ học của hệ số kiên cố theo Prô-tô-đia-cô- nốp fkp?","options":["Là cường độ quy đổi của đá.","Là hệ số ma sát quy đổi của nền.","Là hệ số thực nghiệm đặc trưng cho áp lực địa tầng.","Là hệ số thực nghiệm đặc trưng cho khả năng tự đứng vững của hang đào"],"answer":1,"explain":""},{"id":854,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết tác dụng của nền xung quanh vỏ hầm lắp ghép thi công theo phương pháp TBM dưới dạng tải trọng nào?","options":["Áp lực bị động.","Áp lực chủ động","Vòm áp lực.","Lực kháng đàn hồi."],"answer":2,"explain":""},{"id":855,"cat":"Thiết kế cầu hầm","text":"Thế nào là bàn mặt cầu sườn hở, bàn mặt cầu sườn kín?","options":["Mặt cầu sườn hở là bản mặt cầu trực hướng có các sườn không liên tục, sườn kín là sườn liên tục trên suốt chiều rộng mặt cầu.","Mặt cầu sườn hở có các sườn là thép bản hoặc chữ T, chữ L còn sườn kín có dạng chữ U, chữ V hoặc lượn sóng.","Mặt cầu sườn hở có các sườn giao nhau nhưng không hàn với nhau, mặt cầu sườn kín hàn với nhau.","Mặt cầu sườn hở là bản mặt cầu bằng thép mắt võng, mặt cầu sườn kín là mặt cầu bằng thép tấm."],"answer":1,"explain":""},{"id":856,"cat":"Thiết kế cầu hầm","text":"Có bao nhiêu giải pháp xử lý vùng mô men âm ở cầu dầm thép liên hợp bản bê tông cốt thép?","options":["2","3","4","5"],"answer":3,"explain":""},{"id":857,"cat":"Thiết kế cầu hầm","text":"Hệ số làn xe m không được dùng cho những trường hợp nào?","options":["Trạng thái giới hạn mới.","Khi số làn chất tải là 2.","Trạng thái mỏi và khi sử dụng hệ số phân bố ngang tính theo các công thức lập sẵn trong Tiêu chuẩn 22TCN 272-05.","Khi sử dụng các phương pháp phân tích chính xác."],"answer":2,"explain":""},{"id":858,"cat":"Thiết kế cầu hầm","text":"Bản bê tông mặt cầu của cầu dầm thép liên hợp bản BTCT có chiều dày bằng 1/12 khoảng cách s giữa hai dầm chủ, khẩu độ tính toán L= 10s. Hãy cho biết chiều rộng hữu hiệu bản bê tông của dầm nằm bên trong kết cấu nhịp nhận giá trị nào trong trong số những đại lượng sau?","options":["12 lần chiều dày của bản cộng với ½ chiều rộng bản cánh dầm thép","Bằng khoảng cách s giữa các dầm.","Bằng 1/4L.","12 lần chiều dày bản cộng với chiều rộng bản cánh dầm thép"],"answer":1,"explain":""},{"id":859,"cat":"Thiết kế cầu hầm","text":"Những tải trọng theo phương dọc cầu tác dụng lên những trụ nằm trong phạm vi nhịp thông thuyền gồm những loại nào?","options":["Lực hãm xe BR, lực ma sát FR, gió WL+WS và lực va tầu CV.","Lực hãm xe BR, lực ma sát, lực gió (dọc) WL+WS và 50% lực va tầu CV.","Lực hãm xe BR, lực ma sát FR, gió WL+WS.","Lực hãm xe BR và lực va tầu CV."],"answer":1,"explain":""},{"id":860,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết nguyên lý xác định vị trí trục trung hòa của mặt cắt dầm BTCT hoặc bê tông ứng suất trước chịu uốn?","options":["Xác định theo nguyên lý hình học tìm trọng tâm tiết diện nguyên của bê tông.","Xác định theo nguyên lý hình học tìm trọng tâm tiết diện tính đổi từ cốt thép sang bê tông.","Từ phương trình cân bằng các thành phần lực trong các loại cốt thép và hợp lực của khối ứng suất vùng bê tông chịu nén.","Dựa vào tỉ lệ giữa chiều cao vùng chịu nén của bê tông và chiều cao có hiệu của tiết diện x/h0 ứng với hàm lượng cốt thép tối đa."],"answer":2,"explain":""},{"id":861,"cat":"Thiết kế cầu hầm","text":"Sức kháng uốn danh định Mn của dầm bê tông ứng suất trước được viết như sau: Hãy cho biết công thức này đúng hay sai? Tại sao?","options":["Sai, vì thiếu thành phần chịu lực của bê tông chịu nén.","Đúng, vì là tổng các mô men so với trọng tâm của vùng bê tông chịu nén.","Chỉ đúng với trường hợp dầm chữ nhật và dầm chữ T khi vùng chịu nén nằm trong bản cánh.","Sai, thiếu thành phần mô men của khối ứng suất vùng bê tông chịu nén."],"answer":2,"explain":""},{"id":862,"cat":"Thiết kế cầu hầm","text":"Khả năng chống nứt của dầm bê tông chịu uốn được thiết kế dựa trên tiêu chí nào?","options":["Khống chế ứng suất kéo trong bê tông đối với dầm BTCT thường.","Không cho xuất hiện ứng suất kéo trong bê tông đối với dầm bê tông ứng suất trước.","Khống chế ứng suất kéo trong cốt thép thường fsa ≤ 0,6fy.","Khống chế độ mở rộng vết nứt."],"answer":2,"explain":""},{"id":863,"cat":"Thiết kế cầu hầm","text":"Để tính độ võng và độ vồng của dầm bê tông chịu uốn, độ cứng của dầm được xem xét như thế nào?","options":["Độ cứng của của tiết diện nguyên: Eclg","Độ cứng của tiết diện tính đổi: Ecltd","Độ cứng của tiết diện nguyên không đàn hồi: 0,85Eclg","Độ cứng của mặt cắt có hiệu: Ecle (trong đó le ≤ Ig)"],"answer":0,"explain":""},{"id":864,"cat":"Thiết kế cầu hầm","text":"Hãy cho biết tỉ lệ giữa chiều dài nhịp biên và chiều dài nhịp chính của cầu dầm liên tục thi công theo công nghệ đúc hẫng cân bằng?","options":["0,80","0,75","0,70","0,65"],"answer":3,"explain":""},{"id":865,"cat":"Thiết kế cầu hầm","text":"Sức kháng cắt danh định của dầm bê tông cốt thép và bê tông ứng suất trước bao gồm những thành phần nào?","options":["Sức kháng cắt của bê tông Vc, của cốt thép đai thường Vs và cốt thép đai dự ứng lực Vp.","Sức kháng cắt của bê tông Vc, của cốt đai thường Vs và của cốt dự ứng lực kéo xiên Vp.","Sức kháng cắt của bê tông Vc, của cốt đai thường nằm trong phạm vi vết nứt xiên góc θ° và phân lực thẳng đứng của cốt thép dự ứng lực kéo xiên Vp","Trị số nhỏ nhất của: Vc phụ thuộc β +Vs trong vết nứt xiên θ° + Vp và Vc không phụ thuộc β + Vp"],"answer":3,"explain":""},{"id":45,"cat":"Quản lý dự án","text":"Trường hợp thuê tư vấn quản lý dự án thì nhiệm vụ, quyền hạn của tư vấn QLDA do ai quyết định?","options":["Do chủ đầu tư thông qua hợp đồng","Do pháp luật quy định","Do người quyết định đầu tư","Cấp trên của tổ chức tư vấn quản lý dự án"],"answer":0,"explain":""},{"id":46,"cat":"Quản lý dự án","text":"Theo quy định của pháp luật xây dựng hiện hành, hợp đồng xây dựng không có hình thức nào dưới đây?","options":["Hợp đồng trọn gói","Hợp đồng theo tỷ lệ %","Hợp đồng theo đơn giá điều chỉnh","Hợp đồng theo đơn giá cố định"],"answer":1,"explain":""},{"id":47,"cat":"Quản lý dự án","text":"Trong quá trình thực hiện hợp đồng, bên nhận thầu có được thay đổi người đại diện quản lý thực hiện hợp đồng không?","options":["Có","Không","Có nhưng phải được sự chấp thuận của bên giao thầu","Cả a, b và c đều không đúng"],"answer":2,"explain":""},{"id":48,"cat":"Quản lý dự án","text":"Nguyên tắc và trình tự giải quyết tranh chấp hợp đồng xây dựng được quy định như thế nào sau đây?","options":["Tôn trọng các thỏa thuận hợp đồng và các cam kết trong quá trình thực hiện hợp đồng, bảo đảm bình đẳng và hợp tác;","Các bên hợp đồng có trách nhiệm tự thương lượng giải quyết tranh chấp, trường hợp các bên hợp đồng không tự thương lượng được thì tranh chấp được giải quyết thông qua hòa giải, trọng tài thương mại hoặc tòa án theo quy định của pháp luật.","Đáp ứng cả a và b","Không cần đáp ứng những yêu cầu trên"],"answer":2,"explain":""},{"id":65,"cat":"Quản lý dự án","text":"Ai có thẩm quyền phê duyệt điều chỉnh dự án đầu tư xây dựng?","options":["Người quyết định đầu tư","Chủ đầu tư","Ban quản lý dự án","Cơ quan quản lý nhà nước có thẩm quyền"],"answer":0,"explain":""},{"id":66,"cat":"Quản lý dự án","text":"Cơ quan chuyên môn về xây dựng là cơ quan nào?","options":["Cơ quan chuyên môn thuộc Bộ Xây dựng","Cơ quan chuyên môn thuộc Bộ Giao thông vận tải, Bộ Công thương, Bộ Nông nghiệp và phát triển nông thôn","Các Sở Xây dựng, Sở Giao thông vận tải, Sở Công thương, Sở Nông nghiệp và phát triển nông thôn","Bao gồm cả a, b và c"],"answer":3,"explain":""},{"id":67,"cat":"Quản lý dự án","text":"Theo quy định của Luật Xây dựng, công tác thẩm định là việc kiểm tra, đánh giá của ai?","options":["Người quyết định đầu tư, chủ đầu tư, cơ quan chuyên môn về xây dựng","Cơ quan chuyên môn của người quyết định đầu tư","Người quyết định đầu tư, chủ đầu tư","Tổ chức tư vấn có đủ điều kiện năng lực hoạt động xây dựng"],"answer":0,"explain":""},{"id":68,"cat":"Quản lý dự án","text":"Đối với dự án sử dụng vốn đầu tư công, người quyết định đầu tư có thể giao đơn vị nào sau đây làm chủ đầu tư?","options":["Ban quản lý dự án đầu tư xây dựng chuyên ngành, Ban quản lý dự án đầu tư xây dựng khu vực;","Cơ quan, tổ chức có kinh nghiệm, năng lực quản lý;","Đáp án a và b đúng","Đơn vị được giao khai thác vận hành công trình"],"answer":2,"explain":""},{"id":69,"cat":"Quản lý dự án","text":"Việc điều chỉnh dự án đầu tư xây dựng sử dụng vốn đầu tư công đã được phê duyệt do ai quyết định?","options":["Người quyết định đầu tư","Chủ đầu tư","Cơ quan chuyên môn về xây dựng","Bao gồm cả a, b và c"],"answer":0,"explain":""},{"id":71,"cat":"Quản lý dự án","text":"Ban quản lý dự án đầu tư xây dựng một dự án là tổ chức như thế nào sau đây?","options":["Là tổ chức trực thuộc chủ đầu tư","Được sử dụng con dấu riêng, được mở tài khoản tại kho bạc nhà nước hoặc ngân hàng thương mại","Chịu trách nhiệm trước pháp luật và chủ đầu tư về hoạt động quản lý dự án của mình.","Bao gồm tất cả những nội dung trên"],"answer":3,"explain":""},{"id":72,"cat":"Quản lý dự án","text":"Trong quá trình lập dự án đầu tư xây dựng, tổ chức tư vấn lập dự án có các nghĩa vụ gì?","options":["Thực hiện theo nội dung hợp đồng đã được ký kết với chủ đầu tư","Chịu trách nhiệm về chất lượng công việc theo hợp đồng đã được ký kết;","Bồi thường thiệt hại khi sử dụng thông tin, tài liệu, tiêu chuẩn, quy chuẩn kỹ thuật, giải pháp kỹ thuật, tổ chức quản lý không phù hợp và vi phạm hợp đồng làm thiệt hại cho chủ đầu tư","Bao gồm a, b và c"],"answer":3,"explain":""},{"id":73,"cat":"Quản lý dự án","text":"Hồ sơ của hợp đồng xây dựng gồm các tài liệu nào dưới đây?","options":["Văn bản thông báo trúng thầu hoặc chỉ định thầu","Các bản vẽ thiết kế và chỉ dẫn kỹ thuật (nếu có), Biên bản đàm phán hợp đồng","Bao gồm đáp án a và b","Không cần các tài liệu quy định tại a và b"],"answer":2,"explain":""},{"id":74,"cat":"Quản lý dự án","text":"Hợp đồng xây dựng có hiệu lực pháp lý khi đáp ứng các điều kiện nào sau đây?","options":["Người tham gia ký kết có đầy đủ năng lực hành vi dân sự;","Đáp ứng các nguyên tắc ký kết hợp đồng theo quy định","Hình thức hợp đồng bằng văn bản và được ký kết bởi người đại diện đúng thẩm quyền theo pháp luật của các bên tham gia hợp đồng. Trường hợp một bên tham gia hợp đồng là tổ chức thì bên đó phải ký tên, đóng dấu theo quy định của pháp luật.","Cần đáp ứng đầy đủ các điều kiện ở trên"],"answer":3,"explain":""},{"id":75,"cat":"Quản lý dự án","text":"Cá nhân không yêu cầu phải có chứng chỉ hành nghề theo quy định khi thực hiện các hoạt động xây dựng nào sau đây?","options":["Thiết kế, giám sát hệ thống thông tin liên lạc, viễn thông trong công trình;","Thiết kế, giám sát công tác hoàn thiện công trình xây dựng như trát, ốp lát, sơn, lắp đặt cửa, nội thất và các công việc tương tự khác không ảnh hưởng đến kết cấu chịu lực của công trình;","Các hoạt động xây dựng đối với công trình cấp IV; công viên cây xanh; đường cáp truyền dẫn tín hiệu viễn thông.","Tất cả các nội dung ở trên"],"answer":3,"explain":""},{"id":77,"cat":"Quản lý dự án","text":"Hội đồng thẩm định hoặc đơn vị được giao nhiệm vụ thẩm định dự án PPP thẩm định Báo cáo nghiên cứu khả thi dự án PPP theo quy định của pháp luật nào sau đây?","options":["Pháp luật về đầu tư xây dựng","Pháp luật về đầu tư theo phương thức đối tác công tư","Pháp luật về đầu tư công","Pháp luật về đầu tư và đầu tư công"],"answer":1,"explain":""},{"id":78,"cat":"Quản lý dự án","text":"Việc quyết định đầu tư xây dựng của người quyết định đầu tư được thể hiện tại quyết định phê duyệt dự án đầu tư xây dựng, không bao gồm nội dung nào sau đây?","options":["Tổ chức tư vấn lập Báo cáo nghiên cứu khả thi (Báo cáo kinh tế - kỹ thuật) đầu tư xây dựng, tổ chức lập khảo sát xây dựng (nếu có); tổ chức tư vấn lập thiết kế cơ sở;","Địa điểm xây dựng và diện tích đất sử dụng;","Phương án lựa chọn nhà thầu;","Loại, nhóm dự án; loại, cấp công trình chính; thời hạn sử dụng theo thiết kế của công trình chính;"],"answer":2,"explain":""},{"id":79,"cat":"Quản lý dự án","text":"Cơ quan chuyên môn về xây dựng từ chối tiếp nhận hồ sơ trình thẩm định Báo cáo nghiên cứu khả thi đầu tư xây dựng trong trường hợp nào sau đây?","options":["Trình thẩm định không đúng với thẩm quyền của cơ quan chuyên môn về xây dựng hoặc người đề nghị thẩm định không đúng thẩm quyền theo quy định","Không thuộc đối tượng phải thẩm định tại cơ quan chuyên môn về xây dựng theo quy định","Hồ sơ trình thẩm định không bảo đảm về tính pháp lý hoặc không hợp lệ theo quy định","Tất cả các trường hợp trên"],"answer":3,"explain":""},{"id":168,"cat":"Quản lý dự án","text":"Trong quá trình thẩm định, trường hợp cơ quan chuyên môn về xây dựng yêu cầu người đề nghị thẩm định lựa chọn tổ chức, cá nhân có đủ điều kiện năng lực để thẩm tra, quy định nào là không đúng sau đây?","options":["Việc lựa chọn tổ chức, cá nhân thẩm tra thiết kế xây dựng thực hiện theo hình thức chỉ định thầu rút gọn","Tổ chức tư vấn thẩm tra phải độc lập về pháp lý, tài chính với chủ đầu tư","Việc lựa chọn tổ chức, cá nhân thẩm tra thiết kế xây dựng thực hiện theo hình thức đấu thầu hạn chế được quy định tại pháp luật về đấu thầu.","Tổ chức tư vấn thẩm tra phải độc lập về pháp lý, tài chính với các nhà thầu tư vấn lập thiết kế xây dựng"],"answer":2,"explain":""},{"id":196,"cat":"Quản lý dự án","text":"Đơn vị nào có trách nhiệm bảo đảm an toàn cho con người, công trình xây dựng, tài sản, thiết bị, phương tiện trong quá trình thi công xây dựng công trình, phòng, chống cháy, nổ và bảo vệ môi trường trong giai đoạn thi công?","options":["Tư vấn giám sát.","Nhà thầu thi công xây dựng","Tư vấn Quản lý dự án.","Đơn vị cung cấp máy, thiết bị thi công."],"answer":1,"explain":""},{"id":197,"cat":"Quản lý dự án","text":"Nhà thầu thi công xây dựng có trách nhiệm xác định vùng nguy hiểm trong thi công xây dựng công trình và thực hiện những công tác nào sau đây?","options":["Tổ chức lập, trình chủ đầu tư chấp thuận biện pháp bảo đảm an toàn cho con người, công trình xây dựng, tài sản, thiết bị, phương tiện trong vùng nguy hiểm trong thi công xây dựng công trình","Rà soát biện pháp bảo đảm an toàn định kỳ, đột xuất để điều chỉnh cho phù hợp với thực tế thi công trên công trường","Cả nội dung a và b","Không phải các nội dung trên"],"answer":2,"explain":""},{"id":204,"cat":"Quản lý dự án","text":"Sơ bộ tổng mức đầu tư, bao gồm nội dung nào sau đây?","options":["Chi phí bồi thường, hỗ trợ và tái định cư (nếu có);","Chi phí xây dựng; chi phí thiết bị; chi phí quản lý dự án;","Chi phí tư vấn đầu tư xây dựng; chi phí khác; chi phí dự phòng.","Các đáp án trên đều đúng"],"answer":3,"explain":""},{"id":205,"cat":"Quản lý dự án","text":"Sơ bộ tổng mức đầu tư xây dựng được ước tính dựa trên nội dung nào sau đây?","options":["Cơ sở quy mô, công suất hoặc năng lực phục vụ theo phương án thiết kế sơ bộ của dự án và suất vốn đầu tư xây dựng","Dữ liệu chi phí của các dự án tương tự về loại, cấp công trình, quy mô, công suất","Dựa trên nội dung a hoặc b","Không căn cứ vào các nội dung trên"],"answer":2,"explain":""},{"id":206,"cat":"Quản lý dự án","text":"Định mức kinh tế - kỹ thuật trong xây dựng gồm những loại định mức nào?","options":["Định mức dự toán xây dựng công trình","Định mức sử dụng vật liệu, định mức lao động, định mức năng suất máy và thiết bị thi công;","Định mức cơ sở","a và c"],"answer":3,"explain":""},{"id":207,"cat":"Quản lý dự án","text":"Việc thẩm định, phê duyệt sơ bộ tổng mức đầu tư xây dựng được thực hiện như thế nào là đúng sau đây?","options":["Thực hiện trước khi thẩm định, phê duyệt Báo cáo nghiên cứu tiền khả thi đầu tư xây dựng theo quy định của pháp luật có liên quan.","Thực hiện đồng thời với việc thẩm định, phê duyệt Báo cáo nghiên cứu tiền khả thi đầu tư xây dựng theo quy định của pháp luật có liên quan.","Thực hiện sau khi có kết quả thẩm định, phê duyệt Báo cáo nghiên cứu tiền khả thi đầu tư xây dựng theo quy định của pháp luật có liên quan.","Các đáp án trên đều đúng"],"answer":1,"explain":""},{"id":208,"cat":"Quản lý dự án","text":"Đơn giá nhân công trong dự toán xây dựng công trình do đơn vị nào sau đây công bố?","options":["Ủy ban nhân dân cấp tỉnh.","Đơn vị tư vấn lập dự toán.","Người quyết định đầu tư.","Chủ đầu tư."],"answer":0,"explain":""},{"id":209,"cat":"Quản lý dự án","text":"Dự toán gói thầu của công trình cấp I thuộc Dự án sử dụng vốn đầu tư công do cơ quan nào dưới đây thẩm định?","options":["Bộ Xây dựng, Bộ quản lý công trình xây dựng chuyên ngành thẩm định.","Sở Xây dựng, Sở quản lý công trình xây dựng chuyên ngành thẩm định","Chủ đầu tư.","Người quyết định đầu tư."],"answer":2,"explain":""},{"id":210,"cat":"Quản lý dự án","text":"Dự toán xây dựng công trình không bao gồm chi phí nào sau đây?","options":["Chi phí bồi thường, hỗ trợ và tái định cư","Chi phí rà phá bom mìn, vật nổ","Chi phí tư vấn xây dựng","Chi phí lưu kho, lưu bãi, lưu Container tại cảng Việt Nam đối với thiết bị nhập khẩu"],"answer":0,"explain":""},{"id":211,"cat":"Quản lý dự án","text":"Đối với dự án sử dụng vốn đầu tư công (không phải là dự án quan trọng quốc gia, không phải dự án do Thủ tướng quyết định đầu tư), cơ quan nào sau đây phê duyệt quyết toán vốn đầu tư?","options":["Người quyết định đầu tư","Bộ Tài chính","Sở Tài chính","Chủ đầu tư"],"answer":0,"explain":""},{"id":213,"cat":"Quản lý dự án","text":"Theo quy định về quản lý chi phí đầu tư xây dựng hiện hành, đơn giá ca máy và thiết bị thi công trên địa bàn địa phương do cơ quan nào sau đây ban hành?","options":["Bộ Xây dựng","Sở Xây dựng","Liên sở Tài chính - Xây dựng","Không đơn vị nào ở trên"],"answer":3,"explain":""},{"id":214,"cat":"Quản lý dự án","text":"Suất vốn đầu tư xây dựng công trình được sử dụng để xác định chỉ tiêu nào dưới đây?","options":["Sơ bộ tổng mức đầu tư xây dựng công trình.","Giá xây dựng tổng hợp công trình.","Dự toán xây dựng công trình.","Chi phí xây dựng trong tổng mức đầu tư xây dựng công trình"],"answer":0,"explain":""},{"id":215,"cat":"Quản lý dự án","text":"Chi phí quản lý dự án không bao gồm những yếu tố nào sau đây?","options":["Bảo hiểm y tế, bảo hiểm thất nghiệp.","Chi phí tổ chức thẩm định dự án đầu tư.","Chi phí nghiệm thu bàn giao công trình.","Chi phí hội nghị, hội thảo, tập huấn, đào tạo."],"answer":2,"explain":""},{"id":253,"cat":"Quản lý dự án","text":"Quản lý thực hiện dự án đầu tư xây dựng bao gồm những nội dung nào sau đây?","options":["Quản lý về phạm vi, kế hoạch công việc;","Quản lý khối lượng công việc; chất lượng xây dựng;","Quản lý tiến độ thực hiện; chi phí đầu tư xây dựng;","Tất cả các nội dung ở trên."],"answer":3,"explain":""},{"id":254,"cat":"Quản lý dự án","text":"Ban quản lý dự án đầu tư xây dựng chuyên ngành, Ban quản lý dự án đầu tư xây dựng khu vực có trách nhiệm gì?","options":["Xác định yêu cầu, nội dung nhiệm vụ lập dự án; cung cấp thông tin, tài liệu cần thiết trong trường hợp thuê tư vấn lập dự án; tổ chức nghiệm thu kết quả lập dự án và lưu trữ hồ sơ dự án đầu tư xây dựng","Kiểm tra, giám sát việc thực hiện dự án; định kỳ báo cáo việc thực hiện dự án với người quyết định đầu tư, cơ quan quản lý nhà nước có thẩm quyền","Thu hồi vốn, trả nợ vốn vay đối với dự án có yêu cầu về thu hồi vốn, trả nợ vốn vay","Tất cả các trách nhiệm tại điểm a, b và c"],"answer":3,"explain":""},{"id":255,"cat":"Quản lý dự án","text":"Tổng thầu xây dựng là nhà thầu ký kết hợp đồng trực tiếp với ai để nhận thầu một số loại công việc của công trình hoặc toàn bộ công việc của dự án đầu tư xây dựng.?","options":["Chủ đầu tư","Nhà thầu phụ","Chủ đầu tư và các nhà thầu phụ","Ban quản lý dự án đầu tư xây dựng"],"answer":0,"explain":""},{"id":257,"cat":"Quản lý dự án","text":"Hoạt động đầu tư xây dựng phải bảo đảm các nguyên tắc nào dưới đây?","options":["Sử dụng hợp lý nguồn lực, tài nguyên tại khu vực có dự án, bảo đảm đúng mục đích dự án được phê duyệt","Đúng trình tự đầu tư xây dựng; tuân thủ tiêu chuẩn, quy chuẩn kỹ thuật, quy định của pháp luật có liên quan.","Bảo đảm chất lượng, tiến độ, an toàn công trình, tính mạng, sức khỏe con người và tài sản; phòng, chống cháy, nổ; bảo vệ môi trường.","Tất cả các nguyên tắc nêu tại a, b và c."],"answer":3,"explain":""},{"id":258,"cat":"Quản lý dự án","text":"Chi phí mua bảo hiểm cho người lao động trong thời gian thi công xây dựng của nhà thầu thi công xây dựng được tính trong chi phí nào?","options":["Trong tổng mức đầu tư","Trong chi phí sản xuất kinh doanh của nhà thầu","Trong dự toán xây dựng","Trong giá trị hợp đồng thi công xây dựng"],"answer":1,"explain":""},{"id":259,"cat":"Quản lý dự án","text":"Những hành vi nào dưới đây bị nghiêm cấm trong hoạt động đầu tư xây dựng?","options":["Khởi công xây dựng công trình khi chưa đủ điều kiện khởi công theo quy định của pháp luật về xây dựng.","Xây dựng công trình không đúng quy hoạch xây dựng; vi phạm chỉ giới xây dựng, cốt xây dựng; xây dựng công trình không đúng với giấy phép xây dựng được cấp.","Vi phạm quy định về an toàn lao động, tài sản, phòng, chống cháy, nổ, an ninh, trật tự và bảo vệ môi trường trong xây dựng.","Tất cả các hành vi nêu tại a, b và c"],"answer":3,"explain":""},{"id":260,"cat":"Quản lý dự án","text":"Đối với dự án nhóm A gồm nhiều dự án thành phần trong đó mỗi dự án thành phần có thể vận hành độc lập, khai thác sử dụng hoặc được phân kỳ đầu tư để thực hiện thì dự án thành phần được quản lý thực hiện như thế nào?","options":["Như dự án nhóm A.","Như một dự án độc lập.","Như một dự án độc lập, nhưng phải được cấp có thẩm quyền cho phép đầu tư chấp thuận.","Như một dự án độc lập, do người quyết định đầu tư quyết định"],"answer":2,"explain":""},{"id":261,"cat":"Quản lý dự án","text":"Đối với dự án sử dụng vốn đầu tư công, trong thời gian thực hiện dự án, giá vật liệu xây dựng trên thị trường biến động tăng hơn so với giá tính trong tổng mức đầu tư được duyệt thì có được điều chỉnh dự án không?","options":["Không","Có, nếu chỉ số giá xây dựng do Bộ Xây dựng, Ủy ban nhân dân cấp tỉnh công bố lớn hơn chỉ số giá xây dựng được sử dụng để tính dự phòng trượt giá trong tổng mức đầu tư dự án được duyệt.","Điều chỉnh hay không là do người quyết định đầu tư quyết định","Điều chỉnh hay không là do cơ quan chuyên môn về xây dựng cho phép"],"answer":1,"explain":""},{"id":262,"cat":"Quản lý dự án","text":"Quy định nào là đúng về việc phân kỳ đầu tư ?","options":["Được thể hiện trong Báo cáo nghiên cứu khả thi đầu tư xây dựng và quyết định đầu tư xây dựng,","Phù hợp với tiến độ, thời gian thực hiện dự án trong nội dung quyết định hoặc chấp thuận chủ trương đầu tư xây dựng","Cả a và b đều đúng","Các đáp án trên là sai"],"answer":2,"explain":""},{"id":263,"cat":"Quản lý dự án","text":"Đối với dự án sử dụng vốn đầu tư công, tiến độ thực hiện dự án có được vượt quá thời gian đã được xác định trong dự án được người quyết định đầu tư phê duyệt không?","options":["Có, nhưng phải được chủ đầu tư chấp thuận","Có, nhưng phải được người quyết định đầu tư chấp thuận","Có, nhưng phải được cơ quan chuyên môn về xây dựng chấp thuận","Không"],"answer":1,"explain":""},{"id":267,"cat":"Quản lý dự án","text":"Ai có trách nhiệm thực hiện lập quyết toán hợp đồng xây dựng?","options":["Chủ đầu tư","Nhà thầu thi công xây dựng công trình","Nhà thầu tư vấn giám sát thi công xây dựng","Ban quản lý dự án đầu tư xây dựng"],"answer":1,"explain":""},{"id":268,"cat":"Quản lý dự án","text":"Khi khởi công xây dựng công trình phải có bước thiết kế nào được phê duyệt?","options":["Thiết kế cơ sở","Thiết kế kỹ thuật","Thiết kế bản vẽ thi công của hạng mục công trình, công trình khởi công đã được phê duyệt và được chủ đầu tư kiểm tra, xác nhận trên bản vẽ","Tất cả các bước thiết kế nêu tại a, b và c."],"answer":2,"explain":""},{"id":269,"cat":"Quản lý dự án","text":"Việc thu hồi đất, giao đất, cho thuê đất, bồi thường, giải phóng mặt bằng xây dựng được thực hiện theo quy định nào?","options":["Quy định của pháp luật về xây dựng","Quy định của pháp luật về đất đai","Quy định của pháp luật về xây dựng và pháp luật về đất đai","Theo quy định của Ủy ban nhân dân cấp tỉnh"],"answer":1,"explain":""},{"id":270,"cat":"Quản lý dự án","text":"Việc bàn giao toàn bộ hoặc một phần mặt bằng xây dựng để thi công là do ai quyết định?","options":["Người quyết định đầu tư quyết định","Chủ đầu tư quyết định","Theo thỏa thuận giữa chủ đầu tư và nhà thầu thi công xây dựng","Chính quyền địa phương quyết định"],"answer":2,"explain":""},{"id":271,"cat":"Quản lý dự án","text":"Tổ chức nào có trách nhiệm lắp đặt biển báo công trình tại công trình?","options":["Chủ đầu tư xây dựng công trình","Nhà thầu thiết kế xây dựng công trình","Nhà thầu chính thi công xây dựng công trình","Nhà thầu phụ thi công xây dựng công trình"],"answer":0,"explain":""},{"id":272,"cat":"Quản lý dự án","text":"Vật liệu, cấu kiện sử dụng vào công trình xây dựng phải tuân thủ theo quy định nào?","options":["Theo đúng thiết kế xây dựng, chỉ dẫn kỹ thuật (nếu có) đã được phê duyệt.","Bảo đảm chất lượng theo tiêu chuẩn, quy chuẩn kỹ thuật và pháp luật về chất lượng sản phẩm hàng hóa.","Theo quy định tại cả đáp án a và b","Theo yêu cầu của chủ đầu tư"],"answer":2,"explain":""},{"id":273,"cat":"Quản lý dự án","text":"Trong quá trình thi công xây dựng công trình, chủ đầu tư có nghĩa vụ gì?","options":["Phối hợp, tham gia với Ủy ban nhân dân các cấp thực hiện việc bồi thường thiệt hại, giải phóng mặt bằng xây dựng để bàn giao cho nhà thầu thi công xây dựng","Thuê tổ chức tư vấn có đủ năng lực hoạt động xây dựng để kiểm định chất lượng công trình khi cần thiết","Lưu trữ hồ sơ xây dựng công trình","Tất cả các nghĩa vụ nêu tại a, b và c"],"answer":3,"explain":""},{"id":274,"cat":"Quản lý dự án","text":"Nhà thầu thi công xây dựng có nghĩa vụ gì?","options":["Chịu trách nhiệm về chất lượng, nguồn gốc của vật tư, nguyên liệu, vật liệu, thiết bị, sản phẩm xây dựng do mình cung cấp sử dụng vào công trình;","Lập bản vẽ hoàn công, tham gia nghiệm thu công trình;","Sử dụng vật liệu đúng chủng loại, bảo đảm yêu cầu theo thiết kế được duyệt","Tất cả các nghĩa vụ nêu tại a, b và c"],"answer":3,"explain":""},{"id":275,"cat":"Quản lý dự án","text":"Theo quy định của pháp luật về xây dựng có mấy cấp sự cố công trình xây dựng?","options":["Một","Hai","Ba","Bốn"],"answer":2,"explain":""},{"id":276,"cat":"Quản lý dự án","text":"Trong thời gian thi công xây dựng, xảy ra sự cố công trình xây dựng thì thẩm quyền giải quyết sự cố thực hiện theo quy định nào?","options":["Theo Luật Xây dựng 50/2014 và 62/2020","Theo Nghị định 06/2021/NĐ-CP","Theo Nghị định 10/2021/NĐ-CP","Theo các quy định tại điểm a, b và c"],"answer":1,"explain":""},{"id":277,"cat":"Quản lý dự án","text":"Việc điều chỉnh đơn giá thực hiện hợp đồng chỉ áp dụng đối với loại hợp đồng xây dựng nào?","options":["Hợp đồng theo đơn giá điều chỉnh và hợp đồng theo thời gian","Hợp đồng trọn gói","Hợp đồng theo đơn giá cố định","Tất cả các loại hợp đồng nêu tại a, b và c"],"answer":0,"explain":""},{"id":1776,"cat":"Quản lý dự án","text":"Chi phí mua bảo hiểm trách nhiệm nghề nghiệp tư vấn thiết kế xây dựng của công trình từ cấp II trở lên thuộc khoản mục chi phí nào trong tổng mức đầu tư xây dựng:","options":["Chi phí tư vấn","Chi phí quản lý dự án","Chi phí khác.","Chi phí dự phòng."],"answer":0,"explain":""},{"id":1777,"cat":"Quản lý dự án","text":"Khi sử dụng định mức dự toán số 1776/BXD-VP ngày 16/8/2017 để tính dự toán thì cần đào bao nhiêu m3 đất nguyên thổ để đắp được 1 m3 đất đắp với hệ số đầm nén K98.","options":["1 m3","1.13 m3","1.07 m3","1.16 m3"],"answer":3,"explain":""},{"id":1778,"cat":"Quản lý dự án","text":"Chi phí quản lý dự án không bao gồm nội dung nào sau đây?","options":["Tiền lương của cán bộ quản lý dự án; tiền công trả cho người lao động theo hợp đồng","Các khoản phụ cấp lương; tiền thưởng; phúc lợi tập thể; các khoản đóng góp (bảo hiểm xã hội; bảo hiểm y tế; bảo hiểm thất nghiệp; kinh phí công đoàn, trích nộp khác theo quy định của pháp luật đối với cá nhân được hưởng lương từ dự án)","Chi phí ứng dụng khoa học công nghệ vào công tác khảo sát thiết kế và lập báo cáo nghiên cứu khả thi","Chi phí thanh toán các dịch vụ công cộng; vật tư văn phòng phẩm; thông tin, tuyên truyền, liên lạc; tổ chức hội nghị có liên quan đến dự án"],"answer":2,"explain":""},{"id":1779,"cat":"Quản lý dự án","text":"Khi điều chỉnh giá trị dự toán gói thầu thuộc dự án đã phê duyệt dẫn tới phải điều chỉnh tổng mức đầu tư xây dựng (sử dụng hết chi phí dự phòng) nhưng không làm thay đổi mức đầu tư đã phê duyệt thì cách thức xử lý là:","options":["Người quyết định đầu tư tổ chức điều chỉnh","Chủ đầu tư tự tổ chức điều chỉnh cơ cấu các khoản mục chi phí, báo cáo người quyết định đầu tư và chịu trách nhiệm về việc điều chỉnh của mình.","Theo quy định không được phép điều chỉnh.","Chủ đầu tư tự tổ chức điều chỉnh và chịu trách nhiệm về việc điều chỉnh của mình."],"answer":1,"explain":""},{"id":1780,"cat":"Quản lý dự án","text":"Lựa chọn phương án đúng về việc sử dụng suất vốn đầu tư:","options":["Có thể dùng để xác định tổng mức đầu tư dự án ở giai đoạn chuẩn bị dự án","Có thể được sử dụng trong việc xác định giá trị quyền sử dụng đất","Có thể được sử dụng để xác định giá trị thực tế của tài sản là sản phẩm xây dựng cơ bản khi xác định giá trị doanh nghiệp để cổ phần hóa theo hướng dẫn của cơ quan quản lý có thẩm quyền.","Tất cả các phương án trên đều đúng"],"answer":3,"explain":""},{"id":1783,"cat":"Quản lý dự án","text":"Chi phí xây dựng công trình phụ trợ phục vụ thi công thuộc chi phí nào trong tổng mức đầu tư của dự án đầu tư xây dựng công trình:","options":["Chi phí xây dựng.","Chi phí khác.","Chi phí quản lý dự án","Tất cả các phương án trên đều đúng."],"answer":0,"explain":""},{"id":1784,"cat":"Quản lý dự án","text":"Trường hợp nhà thầu thi công xây dựng công trình phải tự tổ chức khai thác và sản xuất các loại vật liệu đất, đá, cát sỏi để phục vụ thi công xây dựng công trình thì chi phí chung tính trong dự toán xác định giá vật liệu bằng:","options":["2,5% trên chi phí nhân công và chi phí máy thi công","2,5% trên chi phí vật liệu, nhân công và chi phí máy thi công","3,5% trên chi phí nhân công và chi phí máy thi công","3,5% trên chi phí vật liệu, nhân công và chi phí máy thi công"],"answer":0,"explain":""},{"id":1785,"cat":"Quản lý dự án","text":"Trường hợp tổng thầu thực hiện hình thức hợp đồng EPC thực hiện một số công việc quản lý dự án thuộc trách nhiệm của chủ đầu tư thì tổng thầu được hưởng chi phí quản lý dự án thế nào sau đây?","options":["Được hưởng một phần chi phí quản lý dự án phù hợp với phạm vi, khối lượng công việc quản lý dự án do chủ đầu tư giao và được thỏa thuận trong hợp đồng tổng thầu.","Được hưởng toàn bộ chi phí quản lý dự án như trường hợp thuê tư vấn quản lý dự án","Quản lý dự án là trách nhiệm của tổng thầu, không có chi phí cho khoản mục này","Các đáp án trên đều sai"],"answer":0,"explain":""},{"id":1787,"cat":"Quản lý dự án","text":"Giá xây dựng tổng hợp bộ phận kết cấu công trình do Bộ Xây dựng công bố:","options":["Bao gồm toàn bộ chi phí cần thiết để hoàn thành một đơn vị khối lượng nhóm, loại công tác xây dựng, đơn vị kết cấu hoặc bộ phận công trình xây dựng.","Là một trong những cơ sở để lập tổng mức đầu tư dự án.","Chưa bao gồm thuế giá trị gia tăng","Phương án a và b."],"answer":3,"explain":""},{"id":1788,"cat":"Quản lý dự án","text":"Chi phí công việc tư vấn đầu tư xây dựng không bao gồm nội dung nào sau đây?","options":["Chi phí nhân công tư vấn (tiền lương, các khoản phụ cấp lương, tiền thưởng, phúc lợi tập thể, các khoản đóng góp bảo hiểm xã hội, bảo hiểm y tế, bảo hiểm thất nghiệp, kinh phí công đoàn, trích nộp khác theo quy định của pháp luật đối với các cá nhân thực hiện công việc tư vấn tại dự án)","Chi phí ứng dụng khoa học công nghệ, quản lý hệ thống thông tin công trình; chi phí thanh toán các dịch vụ công cộng, vật tư văn phòng phẩm, thông tin, liên lạc","Chi phí thực hiện các công việc: giám sát, đánh giá đầu tư; thẩm định thiết kế xây dựng triển khai sau thiết kế cơ sở và thẩm định dự toán xây dựng","Chi phí thuê mướn, sửa chữa, mua sắm tài sản phục vụ tư vấn cho dự án (nếu có); chi phí quản lý của tổ chức tư vấn; chi phí khác; thu nhập chịu thuế tính trước"],"answer":2,"explain":""},{"id":1790,"cat":"Quản lý dự án","text":"Giá ca máy chờ đợi được xác định gồm các chi phí:","options":["50% chi phí khấu hao, 50% chi phí nhân công điều khiển và chi phí khác của máy.","50% chi phí khấu hao, 50% chi phí nhân công và 50% chi phí khác.","Chi phí khấu hao và chi phí nhân công.","50% chi phí khấu hao"],"answer":0,"explain":""},{"id":1791,"cat":"Quản lý dự án","text":"Giá ca máy được điều chỉnh theo những phương pháp nào dưới đây?","options":["Bù trừ trực tiếp.","Hệ số điều chỉnh.","Chỉ số giá xây dựng.","Tất cả các phương án trên."],"answer":3,"explain":""},{"id":1792,"cat":"Quản lý dự án","text":"Quy định nào sau đây về thu hồi tiền tạm ứng là đúng?","options":["Phải đảm bảo thu hồi hết khi giá trị thanh toán khối lượng hoàn thành đạt 80% giá trị hợp đồng.","Phải đảm bảo thu hồi hết khi giá trị thanh toán khối lượng hoàn thành đạt 90% giá trị hợp đồng.","Bắt buộc thu hồi tạm ứng từ lần thanh toán đầu tiên theo tỷ lệ phần trăm tiền tạm ứng và đảm bảo thu hồi hết khi giá trị thanh toán khối lượng hoàn thành đạt 80% giá trị hợp đồng.","Bắt buộc thu hồi tạm ứng từ lần thanh toán đầu tiên theo tỷ lệ phần trăm tiền tạm ứng và đảm bảo thu hồi hết khi giá trị thanh toán khối lượng hoàn thành đạt 80% giá trị hợp đồng."],"answer":0,"explain":""},{"id":1793,"cat":"Quản lý dự án","text":"Chi phí thuê tư vấn nước ngoài được xác định như thế nào là đúng sau đây?","options":["Phù hợp với loại công việc tư vấn trên cơ sở số lượng chuyên gia, trình độ chuyên gia tư vấn, thời gian làm việc của chuyên gia, mức tiền lương của chuyên gia của quốc gia và khu vực dự kiến thuê và các chi phí cần thiết khác để hoàn thành công việc tư vấn","Phù hợp với bằng cấp chuyên môn của chuyên gia tư vấn và thời gian làm việc của chuyên gia","Được tính trên cơ sở định mức chi phí tư vấn theo quy định chung","Được tính chung đối với chi phí chuyên gia mang tính đặc thù"],"answer":0,"explain":""},{"id":1794,"cat":"Quản lý dự án","text":"Theo quy định hiện hành, đối với máy có giá trị từ 30 triệu đồng trở lên, giá trị thu hồi được tính bằng bao nhiêu % của nguyên giá máy và thiết bị thi công xây dựng?","options":["5%.","10%.","15%.","20%."],"answer":1,"explain":""},{"id":1795,"cat":"Quản lý dự án","text":"Theo quy định hiện hành, có bao nhiêu khoản mục chi phí trong tổng mức đầu tư xây dựng?","options":["5 khoản mục","6 khoản mục","7 khoản mục","8 khoản mục"],"answer":2,"explain":""},{"id":1796,"cat":"Quản lý dự án","text":"Theo quy định hiện hành, sơ bộ tổng mức đầu tư xây dựng là một nội dung của:","options":["Báo cáo nghiên cứu khả thi đầu tư xây dựng","Báo cáo nghiên cứu tiền khả thi đầu tư xây dựng","Báo cáo kinh tế - kỹ thuật đầu tư xây dựng","Báo cáo lập dự án đầu tư xây dựng"],"answer":1,"explain":""},{"id":1797,"cat":"Quản lý dự án","text":"Quyết định phê duyệt dự án đầu tư xây dựng của người quyết định đầu tư không bao gồm nội dung nào sau đây ?","options":["Loại, nhóm dự án; loại, cấp công trình chính; thời hạn sử dụng theo thiết kế của công trình chính;","Biện pháp thi công chủ yếu, biện pháp đảm bảo an toàn và môi trường xây dựng;","Số bước thiết kế, danh mục tiêu chuẩn chủ yếu được lựa chọn;","Tổng mức đầu tư; giá trị các khoản mục chi phí trong tổng mức đầu tư;"],"answer":1,"explain":""},{"id":1798,"cat":"Quản lý dự án","text":"Dự án đầu tư xây dựng phải thực hiện quyết toán vốn đầu tư xây dựng trong trường hợp nào sau đây?","options":["Sau khi công trình của dự án được hoàn thành bàn giao đưa vào sử dụng","Dự án bị dừng thực hiện vĩnh viễn khi cấp có thẩm quyền có văn bản dừng hoặc cho phép chấm dứt thực hiện dự án.","Trong trường hợp a hoặc b","Khi người quyết định đầu tư yêu cầu"],"answer":2,"explain":""},{"id":1799,"cat":"Quản lý dự án","text":"Theo quy định hiện hành, phát biểu nào dưới đây về Suất vốn đầu tư do Bộ Xây dựng công bố là đúng:","options":["Suất vốn đầu tư bao gồm các chi phí: xây dựng, thiết bị, quản lý dự án đầu tư xây dựng, tư vấn đầu tư xây dựng, các khoản chi phí khác và chi phí dự phòng. Suất vốn đầu tư tính toán đã bao gồm thuế giá trị gia tăng cho các chi phí nêu trên.","Suất vốn đầu tư bao gồm các chi phí: xây dựng, thiết bị, quản lý dự án đầu tư xây dựng, tư vấn đầu tư xây dựng và các khoản chi phí khác. Suất vốn đầu tư tính toán chưa bao gồm thuế giá trị gia tăng cho các chi phí nêu trên.","Suất vốn đầu tư chưa bao gồm chi phí thực hiện một số loại công việc theo yêu cầu riêng của dự án/công trình xây dựng cụ thể như chi phí bồi thường, hỗ trợ và tái định cư, Lãi vay trong thời gian thực hiện đầu tư xây dựng, vốn lưu động ban đầu, Chi phí dự phòng trong tổng mức đầu tư,...","Không phát biểu nào đúng."],"answer":2,"explain":""},{"id":1800,"cat":"Quản lý dự án","text":"Trong các chỉ tiêu sau, chỉ tiêu nào là suất vốn đầu tư?","options":["300 triệu đồng/Dầm bê tông cốt thép dự ứng lực mác 40Mpa, dầm I, dài 18m.","290 nghìn đồng/m2 mặt đường cấp phối đá dăm láng nhựa tiêu chuẩn 3.0kg/m2, mô đun đàn hồi Eyc ≥ 80MpA.","6. 570.000 đồng/m2 sàn nhà chung cư ≤ 7 tầng.","Tất cả các chỉ tiêu trên"],"answer":2,"explain":""},{"id":1801,"cat":"Quản lý dự án","text":"Trong các chỉ tiêu sau, chỉ tiêu nào là giá xây dựng tổng hợp bộ phận kết cấu công trình?","options":["300 triệu đồng/ Dầm bê tông cốt thép dự ứng lực mác 40Mpa, dầm I, dài 18m.","54 triệu đồng/cháu mẫu giáo khi quy mô đầu tư xây dựng nhà trẻ 75 < số cháu ≤ 125.","Cả hai phương án a và b.","Không có chỉ tiêu nào là giá xây dựng tổng hợp bộ phận kết cấu công trình."],"answer":0,"explain":""},{"id":1802,"cat":"Quản lý dự án","text":"Dòng tiền của dự án theo quan điểm của ngân hàng được xác định bằng:","options":["Tổng khấu hao và lợi nhuận","Lợi nhuận sau thuế","Tổng dòng thu bằng tiền trừ đi tổng dòng chi bằng tiền, bao gồm chi trả lãi vay","Tổng dòng thu bằng tiền trừ đi tổng dòng chi bằng tiền không bao gồm tiền vay và trả nợ vay"],"answer":3,"explain":""},{"id":1803,"cat":"Quản lý dự án","text":"Khi sử dụng phương pháp đánh giá dự án bằng giá trị hiện tại thuần (Net Present Value), quyết định chấp nhận dự án nếu:","options":["NPV bằng đầu tư ban đầu","NPV có thể <0 nhưng IRR (Internal Rate of Return) tối thiểu bằng lãi suất tiền gửi ngân hàng","NPV>0","NPV có thể lớn hơn hoặc nhỏ hơn 0 nhưng IRR của dự án lớn hơn lãi suất cho vay."],"answer":2,"explain":""},{"id":1804,"cat":"Quản lý dự án","text":"Phân tích hiệu quả tài chính dự án luôn luôn được sử dụng bằng đơn vị:","options":["Quy ước","Hiện vật và tiền tệ","Tiền tệ.","Đơn vị nào là do chủ đầu tư lựa chọn."],"answer":2,"explain":""},{"id":1805,"cat":"Quản lý dự án","text":"Hệ thống chỉ số giá xây dựng được công bố theo quy định hiện hành bao gồm:","options":["Chỉ số giá xây dựng quốc gia, chỉ số giá xây dựng theo loại công trình","Chỉ số giá xây dựng quốc gia, chỉ số giá xây dựng theo loại công trình, theo cơ cấu chi phí, theo yếu tố chi phí","Chỉ số giá xây dựng quốc gia, chỉ số giá xây dựng theo loại công trình, theo cơ cấu chi phí.","Chỉ số giá xây dựng quốc gia, chỉ số giá xây dựng theo loại công trình, theo cơ cấu chi phí, theo yếu tố chi phí, chỉ số giá xây dựng cấp cơ sở."],"answer":1,"explain":""},{"id":1806,"cat":"Quản lý dự án","text":"Việc thanh toán hợp đồng xây dựng được thực hiện như thế nào là đúng sau đây?","options":["Phải phù hợp với loại hợp đồng, giá hợp đồng và các điều kiện trong hợp đồng mà các bên đã ký kết.","Khi thanh toán theo các thỏa thuận trong hợp đồng các bên không phải ký phụ lục hợp đồng, trừ trường hợp bổ sung công việc chưa có trong hợp đồng.","Đáp án a và b đúng","Không đáp án nào là đúng"],"answer":2,"explain":""},{"id":1808,"cat":"Quản lý dự án","text":"Dự án đầu tư xây dựng công trình lập tháng 6/2015 gồm có 1 tòa nhà chung cư cao 20 tầng và 1 chung cư cao 15 tầng, ngoài ra còn đường nội bộ, cổng hàng rào và nhà bảo vệ. Hỏi chi phí tư vấn thiết kế xây dựng trong tổng mức đầu tư xây dựng của dự án tính thế nào là đúng?","options":["Tính dự toán chi phí xây dựng các công trình trong tổng mức đầu tư và tra định mức chi phí thiết kế công trình dân dụng. Chi phí tư vấn thiết kế tính ra như trên chưa có thuế giá trị gia tăng.","Tính dự toán chi phí xây dựng các công trình trong tổng mức đầu tư và tra định mức chi phí thiết kế công trình dân dụng. Chi phí tư vấn thiết kế tính ra như trên đã có thuế giá trị gia tăng.","Tra định mức chi phí tỷ lệ cho từng loại công trình theo giá trị chi phí xây dựng trước thuế. Cộng các chi phí tư vấn thiết kế của tất cả các công trình tính được chi phí tư vấn thiết kế của dự án. Chi phí tư vấn thiết kế tính ra như trên chưa có thuế giá trị gia tăng.","Tra định mức chi phí tỷ lệ cho từng công trình theo giá trị chi phí xây dựng trước thuế của từng hạng mục. Cộng các chi phí tư vấn thiết kế của tất cả các hạng mục tính được chi phí tư vấn thiết kế của dự án. Chi phí tư vấn thiết kế tính ra như trên đã có thuế giá trị gia tăng."],"answer":2,"explain":""},{"id":1809,"cat":"Quản lý dự án","text":"Định mức dự toán xây dựng công trình được xác định trên cơ sở:","options":["Định mức chi phí","Định mức cơ sở","Định mức kinh tế - kỹ thuật","Tất cả các phương án trên"],"answer":1,"explain":""},{"id":1810,"cat":"Quản lý dự án","text":"Định mức kinh tế - kỹ thuật gồm:","options":["Định mức cơ sở, định mức dự toán xây dựng công trình và định mức chi phí","Định mức sử dụng vật liệu, định mức lao động, định mức năng suất máy và thiết bị thi công","Định mức cơ sở và định mức dự toán xây dựng công trình.","Định mức dự toán xây dựng công trình và định mức chi phí"],"answer":2,"explain":""},{"id":1811,"cat":"Quản lý dự án","text":"Khi xác định định mức dự toán xây dựng công trình mới, việc tính toán hao phí nhân công được xác định theo phương pháp nào sau đây?","options":["Theo dây chuyền công nghệ tổ chức thi công","Theo số liệu thống kê của công trình đã và đang thực hiện có điều kiện, biện pháp thi công tương tự","Theo số liệu khảo sát thực tế","Tất cả các đáp án trên đều đúng"],"answer":3,"explain":""},{"id":1813,"cat":"Quản lý dự án","text":"Giá xây dựng tổng hợp là cơ sở để xác định?","options":["Tổng mức đầu tư xây dựng, dự toán xây dựng công trình và dự toán gói thầu xây dựng.","Dự toán xây dựng công trình và dự toán gói thầu xây dựng","Tổng mức đầu tư xây dựng và dự toán xây dựng công trình","Tổng mức đầu tư và dự toán gói thầu."],"answer":2,"explain":""},{"id":1814,"cat":"Quản lý dự án","text":"Suất vốn đầu tư xây dựng không bao gồm những nội dung nào sau đây?","options":["Chi phí xây dựng; chi phí thiết bị","Chi phí tư vấn đầu tư xây dựng; một số khoản mục chi phí khác và thuế giá trị gia tăng cho các chi phí nêu trên","Chi phí dự phòng và chi phí thực hiện một số loại công việc theo yêu cầu riêng của dự án, công trình","Chi phí quản lý dự án"],"answer":2,"explain":""},{"id":1815,"cat":"Quản lý dự án","text":"Phí thẩm định thiết kế cơ sở của dự án đầu tư xây dựng công trình thực hiện theo quy định của cơ quan nào?","options":["UBND cấp tỉnh;","Bộ Tài chính;","Bộ Xây dựng","Liên Bộ Tài chính - Xây dựng"],"answer":1,"explain":""},{"id":1816,"cat":"Quản lý dự án","text":"Phí thẩm định dự án đầu tư xây dựng công trình thuộc khoản mục chi phí nào trong Tổng mức đầu tư dự án theo phương án trả lời dưới đây là đúng?","options":["Chi phí quản lý dự án;","Chi phí tư vấn đầu tư xây dựng công trình;","Chi phí khác","Chi phí xây dựng"],"answer":2,"explain":""},{"id":1817,"cat":"Quản lý dự án","text":"Với công trình sử dụng vốn đầu tư công, trường hợp nào được điều chỉnh dự toán xây dựng đã được phê duyệt:","options":["Nhà thầu chào giá cao hơn.","Khi phát sinh khối lượng của hợp đồng thực hiện theo hình thức trọn gói.","Xảy ra trường hợp bất khả kháng như thiên tai, hỏa hoạn, động đất,...","Tất cả các phương án trên"],"answer":2,"explain":""},{"id":1818,"cat":"Quản lý dự án","text":"Chi phí chung của chi phí xây dựng gồm những chi phí nào sau đây:","options":["Chi phí quản lý doanh nghiệp;","Chi phí điều hành sản xuất tại công trường, chi phí phục vụ công nhân;","Chi phí phục vụ thi công tại công trường và một số chi phí phục vụ cho quản lý khác của doanh nghiệp;","Tất cả các mục trên"],"answer":3,"explain":""},{"id":1819,"cat":"Quản lý dự án","text":"Hố móng hình chữ nhật, đào mở mái taluy có kích thước như hình vẽ dưới, đáy dưới và đáy trên song song cách đều nhau, chọn một đáp án sau đây có công thức tính đúng khối lượng đào đất: S1: Diện tích đáy hố đào. S2: Diện tích miệng hố đào (S2//S1). S3: Diện tích tiết diện cách đều S1 và S2. H: Khoảng cách giữa hai đáy.","options":["V = (S1+S2+S3)*H/6","V = (S1+S2+4S3)*H/6","V = [(a1*b1+a2*b2+(a1+a2)*(b1+b2)]*H/6","B và C đều đúng"],"answer":3,"explain":""},{"id":2,"cat":"Khảo sát xây dựng","text":"Theo quy định của pháp luật về xây dựng, hoạt động xây dựng gồm các công việc nào dưới đây?","options":["Lập quy hoạch xây dựng, lập dự án đầu tư xây dựng công trình, khảo sát xây dựng","Thiết kế xây dựng, thi công xây dựng, giám sát xây dựng, quản lý dự án, lựa chọn nhà thầu, nghiệm thu, bàn giao đưa công trình vào khai thác sử dụng","Bảo hành, bảo trì công trình xây dựng và hoạt động khác có liên quan đến xây dựng công trình","Các công việc nêu tại điểm a, b và c"],"answer":3,"explain":""},{"id":3,"cat":"Khảo sát xây dựng","text":"Dự án đầu tư xây dựng sử dụng vốn ODA thì thực hiện theo quy định nào?","options":["Theo quy định của Hiệp định vay vốn mà Việt Nam ký kết với tổ chức cho vay","Theo pháp luật về xây dựng","Theo quy định của Hiệp định vay vốn mà Việt Nam ký kết với tổ chức cho vay, các quy định của pháp luật về xây dựng và pháp luật khác liên quan","Theo quy định của Hiệp định vay vốn mà Việt Nam ký kết với tổ chức cho vay và các quy định của pháp luật về xây dựng"],"answer":2,"explain":""},{"id":4,"cat":"Khảo sát xây dựng","text":"Việc áp dụng tiêu chuẩn, quy chuẩn kỹ thuật trong hoạt động đầu tư xây dựng phải tuân thủ theo những nguyên tắc nào?","options":["Tuân thủ Quy chuẩn kỹ thuật quốc gia","Tiêu chuẩn được viện dẫn trong quy chuẩn kỹ thuật hoặc văn bản quy phạm pháp luật khác có liên quan","Tiêu chuẩn được áp dụng trong hoạt động đầu tư xây dựng theo nguyên tắc tự nguyện","Tất cả các quy định tại a, b và c"],"answer":3,"explain":""},{"id":5,"cat":"Khảo sát xây dựng","text":"Việc giám sát đánh giá đầu tư đối với các dự án đầu tư xây dựng sử dụng vốn đầu tư công, vốn nhà nước ngoài đầu tư công căn cứ vào các quy định nào?","options":["Pháp luật về xây dựng","Pháp luật về đầu tư công","Pháp luật về đầu tư công và pháp luật về xây dựng","Pháp luật về đầu tư công, pháp luật về xây dựng và pháp luật khác có liên quan"],"answer":3,"explain":""},{"id":6,"cat":"Khảo sát xây dựng","text":"Những chủ thể nào bắt buộc phải mua bảo hiểm công trình trong thời gian thi công xây dựng đối với công trình có ảnh hưởng đến an toàn cộng đồng, môi trường, công trình có yêu cầu kỹ thuật đặc thù, điều kiện thi công xây dựng phức tạp?","options":["Chủ đầu tư xây dựng công trình","Nhà thầu thi công xây dựng công trình","Nhà thầu tư vấn thiết kế xây dựng công trình","Cả 3 chủ thể nêu tại a, b và c"],"answer":0,"explain":""},{"id":7,"cat":"Khảo sát xây dựng","text":"Nội dung nào sau đây là đúng quy định về trách nhiệm mua bảo hiểm bắt buộc trong hoạt động đầu tư xây dựng?","options":["Chủ đầu tư mua bảo hiểm công trình trong thời gian xây dựng đối với công trình có ảnh hưởng đến an toàn cộng đồng, môi trường, công trình có yêu cầu kỹ thuật đặc thù, điều kiện thi công xây dựng phức tạp;","Nhà thầu tư vấn mua bảo hiểm trách nhiệm nghề nghiệp tư vấn đầu tư xây dựng đối với công việc khảo sát xây dựng, thiết kế xây dựng của công trình xây dựng từ cấp II trở lên;","Cả nội dung a và b đều đúng","Các nội dung trên đều sai"],"answer":2,"explain":""},{"id":8,"cat":"Khảo sát xây dựng","text":"Dự án đầu tư xây dựng được phân thành loại và nhóm A, B, C đối với các nguồn vốn nào?","options":["Nguồn vốn đầu tư công","Nguồn vốn nhà nước ngoài đầu tư công","Nguồn vốn khác không phải nguồn vốn nêu tại điểm a và b","Tất cả các nguồn vốn nêu tại điểm a, b và c."],"answer":3,"explain":""},{"id":9,"cat":"Khảo sát xây dựng","text":"Đối với công trình cấp II và cấp III, quy định về thời gian thẩm định thiết kế xây dựng triển khai sau thiết kế cơ sở của cơ quan chuyên môn về xây dựng tính từ ngày nhận đủ hồ sơ hợp lệ như thế nào là đúng sau đây?","options":["Không quá 40 ngày","Không quá 30 ngày","Không quá 25 ngày","Không quá 20 ngày"],"answer":1,"explain":""},{"id":10,"cat":"Khảo sát xây dựng","text":"Theo quy định của pháp luật về xây dựng, những công tác gì được liệt kê dưới đây thuộc giai đoạn chuẩn bị dự án?","options":["Quyết định hoặc chấp thuận chủ trương đầu tư","Lập, thẩm định, phê duyệt Báo cáo nghiên cứu khả thi đầu tư xây dựng","Xin cấp phép xây dựng","Bao gồm công tác a và b"],"answer":3,"explain":""},{"id":91,"cat":"Khảo sát xây dựng","text":"Trong hoạt động xây dựng có các loại hình khảo sát xây dựng nào?","options":["Khảo sát địa hình","Khảo sát địa chất công trình","Khảo sát địa chất thủy văn","Bao gồm cả 3 loại hình nêu tại a, b và c"],"answer":3,"explain":""},{"id":92,"cat":"Khảo sát xây dựng","text":"Nhiệm vụ khảo sát xây dựng được lập phục vụ công tác nào sau đây?","options":["Lập tổng mức đầu tư xây dựng","Lập dự án đầu tư xây dựng, thiết kế xây dựng công trình","Đáp án a và b đều đúng","Đáp án a và b đều sai"],"answer":1,"explain":""},{"id":93,"cat":"Khảo sát xây dựng","text":"Đối với công tác khảo sát xây dựng, nội dung nào sau đây không thuộc trách nhiệm của Chủ đầu tư?","options":["Lựa chọn nhà thầu khảo sát xây dựng, giám sát khảo sát xây dựng trong trường hợp không tự thực hiện khảo sát xây dựng;","Cung cấp cho nhà thầu khảo sát xây dựng thông tin, tài liệu có liên quan đến công tác khảo sát;","Bồi thường thiệt hại khi cung cấp thông tin, tài liệu không phù hợp, vi phạm hợp đồng khảo sát xây dựng;","Điều chỉnh nhiệm vụ khảo sát xây dựng theo yêu cầu của nhà thầu thiết kế"],"answer":3,"explain":""},{"id":94,"cat":"Khảo sát xây dựng","text":"Trong quá trình thực hiện khảo sát xây dựng, Nhiệm vụ khảo sát xây dựng được sửa đổi bổ sung khi nào?","options":["Phát hiện các yếu tố khác thường có thể ảnh hưởng trực tiếp đến giải pháp thiết kế;","Khi có thay đổi nhiệm vụ thiết kế cần phải bổ sung nhiệm vụ khảo sát xây dựng;","Khi đơn vị khảo sát thay đổi nhân lực và thiết bị khảo sát xây dựng;","Đáp án a và b;"],"answer":3,"explain":""},{"id":95,"cat":"Khảo sát xây dựng","text":"Nhà thầu khảo sát xây dựng chịu trách nhiệm về chất lượng công tác khảo sát xây dựng do mình thực hiện thế nào?","options":["Nhà thầu hoàn thành trách nhiệm khi bản vẽ thi công được thẩm định và phê duyệt bởi cấp có thẩm quyền;","Kết quả thẩm định hay phê duyệt kết quả khảo sát không làm giảm trách nhiệm của Nhà thầu;","Nhà thầu hoàn thành trách nhiệm khi công trình được nghiệm thu đưa vào khai thác sử dụng;","Nhà thầu được giảm trách nhiệm khi báo cáo khảo sát xây dựng được chấp thuận bởi cấp có thẩm quyền;"],"answer":1,"explain":""},{"id":96,"cat":"Khảo sát xây dựng","text":"Nhà thầu khảo sát xây dựng có được giảm trách nhiệm đối với chất lượng công tác khảo sát xây dựng? Khi:","options":["Hồ sơ thiết kế đã được thẩm tra và thẩm định xong;","Báo cáo khảo sát xây dựng được đơn vị thẩm tra đánh giá đạt yêu cầu;","Chủ đầu tư đã chấp thuận và phê duyệt báo cáo kết quả khảo sát xây dựng;","Không được giảm trách nhiệm trong những tình huống trên;"],"answer":3,"explain":""},{"id":97,"cat":"Khảo sát xây dựng","text":"Báo cáo kết quả khảo sát xây dựng không cần có những nội dung nào dưới đây?","options":["Những căn cứ thực hiện, quy trình và phương pháp khảo sát xây dựng;","Các chi phí thực hiện theo dự toán và chi phí phát sinh trong quá trình khảo sát xây dựng;","Khối lượng đã thực hiện, kết quả và số liệu sau khi thí nghiệm phân tích;","Khái quát về vị trí và điều kiện tự nhiên của khu vực khảo sát xây dựng, đặc điểm, quy mô, tính chất của công trình."],"answer":1,"explain":""},{"id":98,"cat":"Khảo sát xây dựng","text":"Nhà thầu khảo sát xây dựng có những trách nhiệm gì dưới đây?","options":["Bố trí đủ người có kinh nghiệm và chuyên môn phù hợp để thực hiện khảo sát theo quy định của hợp đồng xây dựng;","Cử người có đủ điều kiện năng lực để làm chủ nhiệm khảo sát và tổ chức thực hiện biện pháp kiểm soát chất lượng khảo sát xây dựng;","Cả nội dung a và b ở trên;","Không cần nội dung nào ở trên;"],"answer":2,"explain":""},{"id":102,"cat":"Khảo sát xây dựng","text":"Nhiệm vụ khảo sát xây dựng được sửa đổi, bổ sung trong các trường hợp nào sau đây?","options":["Trong quá trình thực hiện khảo sát xây dựng, phát hiện các yếu tố khác thường có thể ảnh hưởng trực tiếp đến giải pháp thiết kế","Trong quá trình thiết kế, nhà thầu thiết kế phát hiện nhiệm vụ khảo sát xây dựng, báo cáo khảo sát xây dựng không đáp ứng yêu cầu thiết kế","Trong quá trình thi công, phát hiện các yếu tố địa chất khác thường","Tất cả các trường hợp ở trên"],"answer":3,"explain":""},{"id":103,"cat":"Khảo sát xây dựng","text":"Trường hợp nào khi điều chỉnh thiết kế phải trình cơ quan chuyên môn về xây dựng thẩm định lại? a.Thay đổi kết cấu chịu lực công trình","options":["Thay đổi vật liệu sử dụng cho công trình","Thay đổi biện pháp tổ chức thi công","Bao gồm cả 3 trường hợp a, b và c"],"answer":0,"explain":""},{"id":104,"cat":"Khảo sát xây dựng","text":"Chỉ dẫn kỹ thuật được phê duyệt cùng với phê duyệt thiết kế, dự toán hay phê duyệt riêng?","options":["Phê duyệt riêng với phê duyệt thiết kế","Phê duyệt cùng với khi phê duyệt thiết kế","Do người có thẩm quyền phê duyệt quyết định","Chỉ dẫn kỹ thuật không phải phê duyệt"],"answer":2,"explain":""},{"id":105,"cat":"Khảo sát xây dựng","text":"Trong quá trình thẩm định, trường hợp lựa chọn tổ chức thẩm tra phục vụ thẩm định, các bên phải tuân thủ quy định nào sau đây?","options":["Tổ chức tư vấn thẩm tra phải độc lập về pháp lý, tài chính với chủ đầu tư;","Tổ chức tư vấn thẩm tra phải độc lập về pháp lý, tài chính với nhà thầu tư vấn lập thiết kế xây dựng;","Tuân thủ cả a và b","Không cần tuân thủ nội dung nào ở trên"],"answer":2,"explain":""},{"id":106,"cat":"Khảo sát xây dựng","text":"Phương án kỹ thuật khảo sát xây dựng cần có những nội dung nào sau đây?","options":["Cơ sở lập phương án kỹ thuật khảo sát xây dựng;","Thành phần, khối lượng công tác khảo sát xây dựng;","Phương pháp, thiết bị khảo sát và phòng thí nghiệm được sử dụng;","Tất cả các nội dung ở trên"],"answer":3,"explain":""},{"id":107,"cat":"Khảo sát xây dựng","text":"Chủ đầu tư có trách nhiệm thế nào trong công tác khảo sát xây dựng?","options":["Kiểm tra hoặc thuê đơn vị tư vấn có đủ điều kiện năng lực để thẩm tra phương án kỹ thuật khảo sát xây dựng","Phê duyệt phương án kỹ thuật khảo sát xây dựng theo quy định của hợp đồng.","Đáp án a và b đúng","Đáp án a hoặc b đúng"],"answer":2,"explain":""},{"id":108,"cat":"Khảo sát xây dựng","text":"Cá nhân có trình độ cao đẳng, trung cấp đã được cấp chứng chỉ hành nghề thiết kế, được chủ trì thiết kế công trình cấp mấy?","options":["Cấp II trở xuống.","Cấp III trở xuống.","Cấp IV.","Không được chủ trì thiết kế xây dựng."],"answer":1,"explain":""},{"id":109,"cat":"Khảo sát xây dựng","text":"Chủ đầu tư không có quyền nào dưới đây?","options":["Tự thực hiện khảo sát xây dựng khi có đủ điều kiện năng lực;","Phê duyệt nhiệm vụ khảo sát xây dựng, phương án kỹ thuật khảo sát do tư vấn thiết kế hoặc do nhà thầu khảo sát lập;","Điều chỉnh nhiệm vụ khảo sát xây dựng theo yêu cầu hợp lý của tư vấn thiết kế xây dựng;","Yêu cầu tư vấn khảo sát sử dụng kết quả khảo sát của dự án liền kề."],"answer":3,"explain":""},{"id":110,"cat":"Khảo sát xây dựng","text":"Chủ đầu tư không có trách nhiệm nào dưới đây?","options":["Lựa chọn nhà thầu khảo sát xây dựng, giám sát khảo sát xây dựng trong trường hợp không tự thực hiện khảo sát xây dựng, giám sát khảo sát xây dựng","Cung cấp cho nhà thầu khảo sát xây dựng thông tin, tài liệu có liên quan đến công tác khảo sát","Trình cơ quan chuyên môn về xây dựng thẩm định phương án kỹ thuật và dự toán cho công tác khảo sát xây dựng","Tổ chức giám sát công tác khảo sát xây dựng; nghiệm thu, phê duyệt kết quả khảo sát theo quy định của pháp luật"],"answer":2,"explain":""},{"id":111,"cat":"Khảo sát xây dựng","text":"Nhà thầu khảo sát xây dựng có quyền nào dưới đây?","options":["Yêu cầu chủ đầu tư và các bên có liên quan cung cấp số liệu, thông tin liên quan theo quy định của hợp đồng để thực hiện khảo sát xây dựng","Từ chối thực hiện yêu cầu ngoài hợp đồng khảo sát xây dựng","Thuê nhà thầu phụ thực hiện khảo sát xây dựng theo quy định của hợp đồng khảo sát xây dựng","Cả 3 phương án trên đều đúng"],"answer":3,"explain":""},{"id":112,"cat":"Khảo sát xây dựng","text":"Nhà thầu khảo sát có nghĩa vụ gì?","options":["Thực hiện đúng yêu cầu khảo sát xây dựng theo quy định của pháp luật về xây dựng và hợp đồng khảo sát xây dựng;","Không phải đề xuất, bổ sung nhiệm vụ khảo sát xây dựng khi phát hiện yếu tố ảnh hưởng trực tiếp đến giải pháp thiết kế;","Không chịu trách nhiệm về quản lý chất lượng khảo sát của nhà thầu phụ (nếu có) và kết quả khảo sát của nhà thầu phụ.","Cả 3 phương án trên đều đúng"],"answer":0,"explain":""},{"id":113,"cat":"Khảo sát xây dựng","text":"Thiết kế xây dựng nhà ở riêng lẻ phải đáp ứng các yêu cầu nào?","options":["Tuân thủ tiêu chuẩn áp dụng, quy chuẩn kỹ thuật","Quy định của pháp luật về sử dụng vật liệu xây dựng","Bảo đảm an toàn chịu lực, an toàn trong sử dụng","Đáp ứng tất cả các yêu cầu nêu tại a, b và c"],"answer":3,"explain":""},{"id":114,"cat":"Khảo sát xây dựng","text":"Trường hợp nào khi xây dựng nhà ở riêng lẻ, hộ gia đình không được tự tổ chức thiết kế xây dựng?","options":["Nhà ở có tổng diện tích sàn xây dựng nhỏ hơn 250 m2","Nhà ở có chiều cao dưới 3 tầng","Nhà ở dưới 3 tầng nhưng có chiều cao trên 12 mét.","Cả 3 trường hợp a, b và c"],"answer":2,"explain":""},{"id":115,"cat":"Khảo sát xây dựng","text":"Báo cáo kết quả khảo sát xây dựng phải có nội dung nào sau đây?","options":["Nhiệm vụ khảo sát xây dựng, quy trình và phương pháp khảo sát xây dựng","Căn cứ thực hiện khảo sát xây dựng, quy trình và phương pháp khảo sát xây dựng","Khái quát về vị trí phương án kỹ thuật công trình","Các đáp án trên đều sai"],"answer":1,"explain":""},{"id":116,"cat":"Khảo sát xây dựng","text":"Khi lập phương án kỹ thuật khảo sát xây dựng cần đảm bảo có những nội dung nào sau đây?","options":["Tiêu chuẩn, quy chuẩn kỹ thuật về khảo sát xây dựng áp dụng","Tổ chức thực hiện và biện pháp kiểm soát chất lượng của nhà thầu khảo sát xây dựng","Tiến độ thực hiện","Tất cả các nội dung trên"],"answer":3,"explain":""},{"id":117,"cat":"Khảo sát xây dựng","text":"Dự án đầu tư xây dựng bệnh viện nhóm B sử dụng vốn đầu tư công, có công trình cấp cao nhất là cấp I do Chủ tịch UBND cấp tỉnh quyết định đầu tư thì phải trình cơ quan nào thẩm định thiết kế xây dựng triển khai sát thiết kế cơ sở?","options":["Cơ quan chuyên môn về xây dựng của Bộ Xây dựng","Sở Xây dựng","Cơ quan chuyên môn của người quyết định đầu tư","Cả 3 phương án A, B và C đều sai"],"answer":1,"explain":""},{"id":118,"cat":"Khảo sát xây dựng","text":"Dự án đầu tư xây dựng bệnh viện nhóm A sử dụng đầu tư công, có công trình cấp cao nhất là cấp II do Chủ tịch UBND cấp tỉnh quyết định đầu tư thì phải trình cơ quan nào thẩm định thiết kế thiết kế xây dựng triển khai sát thiết kế cơ sở?","options":["Cơ quan chuyên môn về xây dựng của Bộ Xây dựng","Sở Xây dựng","Sở Kế hoạch và đầu tư","Cơ quan chuyên môn của người quyết định đầu tư"],"answer":0,"explain":""},{"id":119,"cat":"Khảo sát xây dựng","text":"Chủ đầu tư có quyền gì trong công tác thiết kế xây dựng?","options":["Tự thực hiện thiết kế xây dựng khi không đủ điều kiện năng lực hoạt động theo quy định","Yêu cầu nhà thầu thiết kế xây dựng sửa đổi, bổ sung thiết kế xây dựng không tuân thủ quy chuẩn xây dựng","Đình chỉ thực hiện hoặc chấm dứt hợp đồng thiết kế xây dựng theo quy định của hợp đồng và quy định của pháp luật có liên quan","Không được giám sát thực hiện hợp đồng thiết kế đã ký kết với nhà thầu"],"answer":2,"explain":""},{"id":120,"cat":"Khảo sát xây dựng","text":"Những nội dung nào sau đây thuộc nhiệm vụ khảo sát xây dựng?","options":["Mục đích và phạm vi khảo sát;","Tiêu chuẩn khảo sát xây dựng được áp dụng;","Khối lượng các loại công tác khảo sát xây dựng (dự kiến) và dự toán chi phí cho công tác khảo sát xây dựng;","Tất cả các nội dung trên"],"answer":3,"explain":""},{"id":121,"cat":"Thiết kế quy hoạch","text":"Để được cấp chứng chỉ hành nghề hoạt động xây dựng, cá nhân phải đáp ứng được điều kiện gì?","options":["Có trình độ chuyên môn phù hợp với nội dung đề nghị cấp chứng chỉ hành nghề","Có thời gian và kinh nghiệm tham gia công việc phù hợp với nội dung đề nghị cấp chứng chỉ hành nghề","Đã qua sát hạch kiểm tra kinh nghiệm nghề nghiệp và kiến thức pháp luật liên quan đến lĩnh vực hành nghề","Tất cả các điều kiện trên"],"answer":3,"explain":""},{"id":122,"cat":"Thiết kế quy hoạch","text":"Cơ quan nào có trách nhiệm tổ chức lập quy hoạch xây dựng?","options":["Bộ Xây dựng","Ủy ban nhân dân các cấp","Chủ đầu tư dự án","Bộ Xây dựng và Ủy ban nhân dân các cấp"],"answer":3,"explain":""},{"id":123,"cat":"Thiết kế quy hoạch","text":"Loại nào dưới đây là Quy hoạch xây dựng?","options":["Quy hoạch bảo quản, tu bổ, phục hồi di tích;","Quy hoạch khu chức năng đặc thù;","Quy hoạch hệ thống đô thị và nông thôn;","Quy hoạch chi tiết nhóm cảng biển, bến cảng, cầu cảng, bến phao, khu nước, vùng nước."],"answer":1,"explain":""},{"id":124,"cat":"Thiết kế quy hoạch","text":"Công tác quy hoạch xây dựng bao gồm những công việc chủ yếu nào sau đây?","options":["Lập, phê duyệt nhiệm vụ và lập, phê duyệt đồ án quy hoạch xây dựng","Tổ chức triển khai, quản lý thực hiện theo quy hoạch được duyệt","Lập, xác định chi phí cho công tác quy hoạch","Tất cả các nội dung trên"],"answer":3,"explain":""},{"id":125,"cat":"Thiết kế quy hoạch","text":"Cấp nào có thẩm quyền phê duyệt nhiệm vụ và đồ án quy hoạch xây dựng khu công nghệ cao?","options":["Thủ tướng Chính phủ","Bộ Xây dựng","Hội đồng nhân dân các huyện trong vùng lập quy hoạch","Ủy ban nhân dân cấp Tỉnh"],"answer":0,"explain":""},{"id":126,"cat":"Thiết kế quy hoạch","text":"Cơ quan nào có thẩm quyền phê duyệt quy hoạch xây dựng vùng huyện?","options":["Ủy ban nhân dân tỉnh","Ủy ban nhân dân huyện","Hội đồng nhân dân tỉnh","Bộ Xây dựng"],"answer":0,"explain":""},{"id":127,"cat":"Thiết kế quy hoạch","text":"Ủy ban nhân dân cấp Tỉnh có thẩm quyền phê duyệt các quy hoạch nào dưới đây:","options":["Toàn bộ các quy hoạch liệt kê dưới đây","Quy hoạch xây dựng vùng liên huyện,","Quy hoạch chung xây dựng khu chức năng, trừ các quy hoạch do Thủ tướng Chính phủ phê duyệt","Quy hoạch xây dựng vùng huyện;"],"answer":0,"explain":""},{"id":128,"cat":"Thiết kế quy hoạch","text":"Quy hoạch xây dựng vùng liên huyện, quy hoạch xây dựng vùng huyện được điều chỉnh khi thuộc trường hợp sau đây?","options":["Có sự điều chỉnh mục tiêu của chiến lược phát triển kinh tế - xã hội, chiến lược phát triển ngành, lĩnh vực làm thay đổi mục tiêu của quy hoạch;","Có sự điều chỉnh của quy hoạch cao hơn làm thay đổi nội dung quy hoạch hoặc có sự mâu thuẫn với quy hoạch cùng cấp;","Có sự thay đổi, điều chỉnh địa giới hành chính làm ảnh hưởng đến tính chất, quy mô không gian lãnh thổ của quy hoạch;","Khi thuộc một trong các trường hợp ở trên"],"answer":3,"explain":""},{"id":129,"cat":"Thiết kế quy hoạch","text":"Trình tự lập, phê duyệt quy hoạch xây dựng?","options":["Lập, phê duyệt Nhiệm vụ quy hoạch xây dựng - Lập, phê duyệt đồ án quy hoạch xây dựng","Lập, phê duyệt Nhiệm vụ quy hoạch xây dựng - Điều tra, khảo sát thực địa, thu thập bản đồ, tài liệu, số liệu về hiện trạng - Lập, phê duyệt đồ án quy hoạch xây dựng","Điều tra, khảo sát thực địa, thu thập bản đồ, tài liệu, số liệu về hiện trạng - Lập, phê duyệt đồ án quy hoạch xây dựng","Lập, phê duyệt Nhiệm vụ quy hoạch xây dựng - Điều tra, khảo sát thực địa, thu thập bản đồ, tài liệu, số liệu về hiện trạng - Lập đồ án quy hoạch xây dựng - Thẩm định, phê duyệt đồ án quy hoạch xây dựng"],"answer":3,"explain":""},{"id":130,"cat":"Thiết kế quy hoạch","text":"Quy hoạch xây dựng vùng liên huyện được lập khi nào?","options":["Theo đề xuất của Sở Xây dựng phù hợp với quy hoạch vùng, quy hoạch tỉnh","Nhằm đáp ứng yêu cầu quản lý, định hướng phát triển, xác định vai trò của từng đơn vị hành chính cấp huyện, xã, thị trấn và các đô thị trong tổng thể phát triển chung của vùng liên huyện, đảm bảo phân bổ nguồn lực quốc gia, tỉnh có hiệu quả","Được Ủy ban nhân dân cấp tỉnh quyết định","Có đầy đủ các cơ sở trên"],"answer":3,"explain":""},{"id":131,"cat":"Thiết kế quy hoạch","text":"Tỷ lệ bản vẽ hồ sơ đồ án quy hoạch xây dựng vùng liên huyện nào đúng?","options":["1/500.000","1/25.000 - 1/500.000","1/25.000 - 1/100.000","1/50.000 - 1/250.000"],"answer":3,"explain":""},{"id":132,"cat":"Thiết kế quy hoạch","text":"Tỷ lệ diện tích chiếm đất của các công trình kiến trúc chính trên diện tích lô đất (không bao gồm diện tích chiếm đất của các công trình ngoài trời như tiểu cảnh trang trí, bể bơi, bãi (sân) đỗ xe, sân thể thao, công trình hạ tầng kỹ thuật) được xác định là khái niệm nào sau đây?","options":["Mật độ xây dựng thuần","Mật độ xây dựng gộp","Cả 2 đáp án trên là đúng","Cả 2 đáp án trên là sai"],"answer":0,"explain":""},{"id":133,"cat":"Thiết kế quy hoạch","text":"Yêu cầu về dự báo trong đồ án quy hoạch không bao gồm nội dung nào sau đây?","options":["Dự báo phải đề cập đến các vấn đề về tai biến thiên nhiên, môi trường, biến đổi khí hậu và nước biển dâng;","Quy hoạch phân khu, quy hoạch chi tiết phải tuân thủ và cụ thể hóa các dự báo của toàn đô thị;","Dự báo về dân số, lao động, đất đai dựa trên cơ sở chuỗi các số liệu với thời gian tối thiểu của 2 năm gần nhất;","Kết quả của dự báo phải đảm bảo phù hợp với khả năng dung nạp, đáp ứng của đất đai, hạ tầng xã hội, hạ tầng kỹ thuật và môi trường."],"answer":2,"explain":""},{"id":134,"cat":"Thiết kế quy hoạch","text":"Những cá nhân nào sau đây bắt buộc phải có chứng chỉ hành nghề trong hồ sơ năng lực thực hiện một đồ án quy hoạch xây dựng?","options":["Chủ nhiệm đồ án và Chủ trì các bộ môn","Chủ nhiệm đồ án","Chủ trì phần kiến trúc","Tất cả các thành viên tham gia thực hiện đồ án quy hoạch xây dựng"],"answer":0,"explain":""},{"id":135,"cat":"Thiết kế quy hoạch","text":"Căn cứ để lập đồ án quy hoạch xây dựng?","options":["Luật, Nghị định, Thông tư hướng dẫn và các quy chuẩn","Hệ thống quy hoạch quốc gia và các quy hoạch có liên quan đã được phê duyệt","Nhiệm vụ quy hoạch được duyệt","Tất cả các căn cứ trên"],"answer":3,"explain":""},{"id":136,"cat":"Thiết kế quy hoạch","text":"Cơ quan nào sau đây có thẩm quyền quyết định điều chỉnh cục bộ quy hoạch?","options":["Cơ quan tổ chức lập quy hoạch","Cơ quan thẩm định quy hoạch","Cơ quan tư vấn lập quy hoạch","Cơ quan phê duyệt quy hoạch"],"answer":3,"explain":""},{"id":138,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, chiều cao công trình xây dựng được tính như thế nào là đúng sau đây?","options":["Chiều tính từ cao độ mặt đất đặt công trình theo quy hoạch được duyệt tới điểm cao nhất của công trình (kể cả mái tum hoặc mái dốc).","Đối với công trình có các cao độ mặt đất khác nhau thì chiều cao tính từ cao độ mặt đất thấp nhất theo quy hoạch được duyệt.","Cả đáp án a và b đúng","Cả đáp án a và b sai"],"answer":2,"explain":""},{"id":139,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, không gian xây dựng ngầm đô thị không bao gồm nội dung nào sau đây?","options":["Công trình công cộng ngầm, công trình giao thông ngầm","Các công trình đầu mối kỹ thuật ngầm và phần ngầm của các công trình xây dựng trên mặt đất","Công trình đường dây, cáp, đường ống kỹ thuật ngầm, hào và tuy nen kỹ thuật","Bao gồm các nội dung trên"],"answer":3,"explain":""},{"id":140,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, Công trình hạ tầng kỹ thuật ngầm theo tuyến có kích thước lớn đủ để đảm bảo cho con người có thể thực hiện các nhiệm vụ lắp đặt, sửa chữa và bảo trì các thiết bị, đường ống kỹ thuật được định nghĩa là công trình nào sau đây?","options":["Tuy-nen kỹ thuật","Hào kỹ thuật","Đường hầm hạ tầng kỹ thuật","Tuyến hầm kỹ thuật"],"answer":0,"explain":""},{"id":141,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, Trong trường hợp bắt buộc phải xây dựng tại các khu vực có nguy cơ xuất hiện hoặc bị ảnh hưởng từ các tai biến thiên nhiên (trượt lở, ngập lụt, lũ...), quy hoạch phải đáp ứng yêu cầu nào sau đây?","options":["Đề xuất phương án phòng tránh thiên tai và cứu hộ cứu nạn","Đề xuất giải pháp giảm thiểu, khắc phục và đảm bảo an toàn cho cộng đồng","Phân vùng các khu vực cấm hoạt động xây dựng","Bao gồm tất cả các nội dung trên"],"answer":1,"explain":""},{"id":142,"cat":"Thiết kế quy hoạch","text":"Nhiệm vụ thiết kế xây dựng không bao gồm nội dung nào sau đây?","options":["Các căn cứ để lập nhiệm vụ thiết kế xây dựng;","Mục tiêu xây dựng công trình;","Các yêu cầu về đáp ứng biện pháp thi công biện pháp an toàn và bảo vệ môi trước xây dựng;","Địa điểm xây dựng công trình; Các yêu cầu về quy hoạch, cảnh quan và kiến trúc của công trình;"],"answer":2,"explain":""},{"id":143,"cat":"Thiết kế quy hoạch","text":"Trong quá trình lập thiết kế xây dựng triển khai sau thiết kế cơ sở, chủ đầu tư được quyết định việc điều chỉnh thiết kế trong trường hợp nào sau đây?","options":["Đáp ứng hiệu quả và yêu cầu sử dụng khi thay đổi về mục đích, công năng công trình;","Đáp ứng hiệu quả và yêu cầu sử dụng khi không làm thay đổi về mục đích, công năng, quy mô, các chỉ tiêu quy hoạch - kiến trúc tại quy hoạch chi tiết xây dựng;","Đáp ứng hiệu quả và yêu cầu sử dụng khi thay đổi về các chỉ tiêu quy hoạch - kiến trúc tại quy hoạch chi tiết xây dựng;","Cả đáp án a và c đúng."],"answer":1,"explain":""},{"id":144,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, Yêu cầu về định hướng tổ chức không gian cấp vùng (huyện, liên huyện) không cần đáp ứng yêu cầu nào sau đây?","options":["Các phân vùng trong đồ án quy hoạch phải được đề xuất dựa trên các đặc trưng về cảnh quan thiên nhiên, đặc điểm kinh tế, xã hội, môi trường và sinh thái vùng","Phân vùng phải lồng ghép với các giải pháp kiểm soát quản lý theo các mức độ: ưu tiên cho xây dựng (đô thị, khu dân cư, khu công nghiệp...)","Đối với khu vực dự báo chịu tác động từ nước biển dâng, phải tính toán đến tác động từ mực nước biển dâng theo các kịch bản của quốc gia;","Hệ thống các đô thị trong vùng phải đảm bảo có khả năng phát triển, mở rộng, thỏa mãn các yêu cầu về môi trường, an toàn cho định cư. Đồ thị phải liên kết thuận lợi với các đô thị khác và với các vùng nông thôn"],"answer":2,"explain":""},{"id":145,"cat":"Thiết kế quy hoạch","text":"Theo Quy chuẩn QCVN 01: 2019/BXD, Tổ chức không gian toàn đô thị không cần phải đáp ứng yêu cầu nào sau đây?","options":["Đối với các thành phố có cấu trúc gồm nhiều đô thị, phải đảm bảo sự liên kết thuận lợi giữa đô thị trung tâm và các đô thị khác, các khu chức năng. Đảm bảo duy trì vùng đệm, vùng sinh thái giữa các đô thị;","Phải dựa trên các giá trị đặc trưng trong từng khu vực về điều kiện tự nhiên, kiến trúc cảnh quan và chức năng đô thị;","Quy hoạch phải xác định được ranh giới khu vực phát triển đô thị và khu vực hạn chế (hoặc không) phát triển đô thị;","Đối với các đô thị dự kiến mở rộng, ranh giới đô thị phải dựa trên các dự báo về quy mô dân số, đất đai, hạ tầng và phải thỏa mãn các yêu cầu về lựa chọn đất xây dựng;"],"answer":1,"explain":""},{"id":147,"cat":"Khảo sát xây dựng","text":"Nhiệm vụ khảo sát xây dựng phải phù hợp với các nội dung nào sau đây?","options":["Loại và nhóm dự án đầu tư xây dựng","Nhiệm vụ thiết kế xây dựng công trình","Chủ trương đầu tư xây dựng","Loại, cấp công trình xây dựng, loại hình khảo sát và bước thiết kế"],"answer":3,"explain":""},{"id":148,"cat":"Khảo sát xây dựng","text":"Chủ đầu tư được tự thực hiện hoặc thuê tổ chức, cá nhân có năng lực hành nghề phù hợp với loại hình khảo sát để giám sát khảo sát xây dựng theo các nội dung nào sau đây?","options":["Kiểm tra năng lực thực tế của nhà thầu khảo sát xây dựng được sử dụng so với phương án khảo sát xây dựng được duyệt và quy định của hợp đồng xây dựng","Theo dõi, kiểm tra việc thực hiện khảo sát xây dựng bao gồm: vị trí khảo sát, khối lượng khảo sát, quy trình thực hiện khảo sát, lưu giữ số liệu khảo sát và mẫu thí nghiệm;","Theo dõi, kiểm tra công tác thí nghiệm trong phòng và thí nghiệm hiện trường; công tác bảo đảm an toàn lao động, an toàn môi trường trong quá trình thực hiện khảo sát.","Tất cả các nội dung trên"],"answer":3,"explain":""},{"id":149,"cat":"Khảo sát xây dựng","text":"Thiết kế xây dựng công trình phải đáp ứng yêu cầu nào dưới đây?","options":["Đáp ứng yêu cầu của nhiệm vụ thiết kế; phù hợp với nội dung dự án đầu tư xây dựng được duyệt, quy hoạch xây dựng, cảnh quan kiến trúc, điều kiện tự nhiên, văn hóa - xã hội tại khu vực xây dựng","Tuân thủ tiêu chuẩn áp dụng, quy chuẩn kỹ thuật, quy định của pháp luật về sử dụng vật liệu xây dựng, đáp ứng yêu cầu về công năng sử dụng, công nghệ áp dụng (nếu có); bảo đảm an toàn chịu lực, an toàn trong sử dụng, mỹ quan, bảo vệ môi trường","Có giải pháp thiết kế phù hợp và chi phí xây dựng hợp lý; bảo đảm đồng bộ trong từng công trình và với các công trình liên quan","Cả 3 yêu cầu nêu tại a, b và c"],"answer":3,"explain":""},{"id":150,"cat":"Khảo sát xây dựng","text":"Thiết kế, dự toán xây dựng công trình triển khai sau thiết kế cơ sở gồm những nội dung chủ yếu gì?","options":["Phương án kiến trúc, phương án công nghệ (nếu có)","Phương án kết cấu, loại vật liệu chủ yếu","Dự toán xây dựng","Bao gồm cả 3 nội dung nêu tại a, b và c"],"answer":3,"explain":""},{"id":151,"cat":"Khảo sát xây dựng","text":"Trên cơ sở bảo đảm sự thống nhất, đồng bộ về nội dung, cơ sở tính toán trong các kết quả thẩm định. Việc thẩm định thiết kế xây dựng triển khai sau thiết kế cơ sở được thực hiện như thế nào là đúng sau đây?","options":["Với toàn bộ các công trình;","Với từng công trình của dự án hoặc bộ phân công trình theo giai đoạn thi công công trình theo yêu cầu của chủ đầu tư;","Có thể thực hiện a hoặc b;","Các đáp án trên đều sai."],"answer":1,"explain":""},{"id":152,"cat":"Khảo sát xây dựng","text":"Đối với dự án sử dụng vốn đầu tư công, ai là người phê duyệt thiết kế bản vẽ thi công và dự toán xây dựng trong trường hợp thiết kế 2 bước?","options":["Người có thẩm quyền quyết định đầu tư","Chủ đầu tư","Ban QLDA đầu tư xây dựng chuyên ngành hoặc Ban QLDA khu vực","Cơ quan chuyên môn của người quyết định đầu tư"],"answer":1,"explain":""},{"id":154,"cat":"Khảo sát xây dựng","text":"Trong trường hợp điều chỉnh thiết kế xây dựng triển khai sau thiết kế cơ sở, cơ quan chuyên môn về xây dựng theo thẩm quyền thực hiện việc thẩm định thiết kế xây dựng điều chỉnh đối với trường hợp nào sau đây?","options":["Điều chỉnh, bổ sung thiết kế xây dựng có thay đổi về địa chất công trình, tải trọng thiết kế, giải pháp kết cấu, vật liệu sử dụng cho kết cấu chịu lực và biện pháp tổ chức thi công có ảnh hưởng đến an toàn chịu lực của công trình;","Khi điều chỉnh dự án đầu tư xây dựng có yêu cầu điều chỉnh thiết kế cơ sở","Cả trường hợp a và b","Không thẩm trường hợp nào ở trên"],"answer":2,"explain":""},{"id":160,"cat":"Khảo sát xây dựng","text":"Cá nhân có trình độ cao đẳng, trung cấp có chứng chỉ hành nghề thiết kế được chủ trì thiết kế công trình cấp mấy?","options":["Cấp II trở xuống","Cấp III trở xuống","Cấp IV","Không được chủ trì thiết kế xây dựng"],"answer":1,"explain":""},{"id":161,"cat":"Khảo sát xây dựng","text":"Dự án nào sau đây yêu cầu phải lập Báo cáo nghiên cứu tiền khả thi đầu tư xây dựng?","options":["Dự án quan trọng quốc gia","Dự án quan trọng quốc gia, dự án nhóm A và nhóm B","Dự án quan trọng quốc gia và dự án nhóm A","Cả ba đáp án trên"],"answer":2,"explain":""},{"id":162,"cat":"Khảo sát xây dựng","text":"Nhiệm vụ khảo sát xây dựng do chủ thể nào lập?","options":["Nhà thầu thiết kế","Tổ chức, cá nhân có đủ điều kiện năng lực","Nhà thầu thiết kế hoặc tổ chức, cá nhân có đủ điều kiện năng lực","Người quyết định đầu tư"],"answer":2,"explain":""},{"id":163,"cat":"Khảo sát xây dựng","text":"Phương án kỹ thuật khảo sát xây dựng do chủ thể nào lập?","options":["Nhà thầu thiết kế","Nhà thầu Khảo sát","Tư vấn giám sát","Chủ đầu tư"],"answer":1,"explain":""},{"id":164,"cat":"Khảo sát xây dựng","text":"Chỉ dẫn kỹ thuật phải phù hợp với nội dung nào sau đây?","options":["Quy chuẩn kỹ thuật,","Tiêu chuẩn áp dụng cho công trình xây dựng được phê duyệt","Theo yêu cầu của thiết kế xây dựng công trình.","Cả phương án a,b,c"],"answer":3,"explain":""},{"id":165,"cat":"Khảo sát xây dựng","text":"Bắt buộc thực hiện lập chỉ dẫn kỹ thuật riêng đối với công trình nào sau đây?","options":["Công trình ảnh hưởng đến an toàn cộng đồng","Toàn bộ các cấp","Cấp đặc biệt, cấp I và cấp II","Công trình quan trọng quốc gia"],"answer":2,"explain":""},{"id":173,"cat":"Khảo sát xây dựng","text":"Trước khi trình cơ quan chuyên môn về xây dựng thẩm định thiết kế, chủ đầu tư có cần phải thuê tư vấn thẩm tra hay không?","options":["Có","Không","Do chủ đầu tư quyết định","Có, nhưng theo yêu cầu của cơ quan chuyên môn về xây dựng"],"answer":2,"explain":""}];
